use rand::SeedableRng;
use rand_pcg::Pcg64;


fn map_filter_string_to_attr(filter: &str) -> u64 {
    let mut attr: u64 = 0;
    for part in filter.split(',') {
        let part = part.trim().to_uppercase();
        if part.is_empty() { continue; }

        if part.starts_with("COST") {
            let val_str = if part.contains('=') {
                part.split('=').last()
            } else {
                part.split('_').last()
            };
            if let Some(s) = val_str {
                if let Ok(threshold) = s.parse::<i32>() {
                    attr |= 0x01000000 | ((threshold as u64) << 25);
                    if part.contains("_LE") { attr |= 0x40000000u64; }
                }
            }
        } else if part.starts_with("GROUP_ID=") || part.starts_with("GROUP_ID_") {
             let gid_str = if part.contains('=') {
                 part.split('=').last()
             } else {
                 part.split('_').last()
             };
              if let Some(s) = gid_str {
                 if let Ok(gid) = s.parse::<i32>() {
                    attr |= 0x10 | ((gid as u64) << 5);
                 }
              }
        } else if part.starts_with("UNIT_") {
            let unit_name = part.replace("UNIT_", "").replace("_ONLY", "");
            let unit_id = match unit_name.as_str() {
                "BIBI" => 0, "LILY_WHITE" | "LILYWHITE" => 2, "QU4RTZ" => 12, "AZUNA" => 11, "DIVERDIVA" => 13, "A_ZU_NA" => 11,
                _ => -1,
            };
            if unit_id >= 0 { attr |= 0x10000 | ((unit_id as u64) << 17); }
        } else if part == "TAPPED" {
            attr |= 0x1000; // Bit 12
        } else if part == "HAS_BLADE_HEART" {
            attr |= 0x2000; // Bit 13
        } else if part == "NOT_HAS_BLADE_HEART" {
            attr |= 0x4000; // Bit 14
        } else if part == "TYPE_MEMBER" {
            attr |= 0x04; // Bit 2 (1<<2 = 4)
        } else if part == "TYPE_LIVE" {
            attr |= 0x08; // Bit 3 (2<<2 = 8)
        } else if part == "AQOURS" {
            attr |= 0x10 | (1 << 5);
        } else if part == "M'S" || part == "μ'S" || part == "U'S" {
            attr |= 0x10 | (0 << 5);
        } else if part.contains("NAME_IN") && part.contains("澁谷かのん") {
            attr |= 1u64 << 48; // Special ID 1 (Moved to avoid collision with Group ID)
        } else if part.contains("NOT_NAME=MY舞") {
            attr |= 2u64 << 48; // Special ID 2 (Moved to avoid collision with Group ID)
        } else if part == "UNIQUE_NAMES=TRUE" || part == "UNIQUE_NAMES" || part == "SAME_UNIQUE_NAMES" {
            attr |= 0x8000; // Bit 15
        } else if part == "SMILE" || part == "PINK" || part == "COLOR_0" {
            attr |= 1u64 << 32;
        } else if part == "PURE" || part == "GREEN" || part == "COLOR_1" {
            attr |= 1u64 << 33;
        } else if part == "COOL" || part == "BLUE" || part == "COLOR_2" {
            attr |= 1u64 << 34;
        } else if part == "ALL_STARS_RED" || part == "RED" || part == "COLOR_3" {
            attr |= 1u64 << 35;
        } else if part == "ALL_STARS_YELLOW" || part == "YELLOW" || part == "COLOR_4" {
            attr |= 1u64 << 36;
        } else if part == "ALL_STARS_BLUE" || part == "LTBLUE" || part == "COLOR_5" {
            attr |= 1u64 << 37;
        } else if part == "ALL_STARS_PURPLE" || part == "PURPLE" || part == "COLOR_6" {
            attr |= 1u64 << 38;
        } else if part.starts_with("BLADE_LE") {
            // BLADE_LE_3 などのブレード制限フィルタ
            let val_str = part.replace("BLADE_LE", "").replace("_", "");
            if let Ok(threshold) = val_str.parse::<i32>() {
                attr |= 0x02000000 | ((threshold as u64) << 25); // Use bit 25 for threshold
                attr |= 0x40000000u64; // LE flag
            }
        } else if part.starts_with("BLADE_GE") {
            // BLADE_GE_5 などのブレード下限制限フィルタ
            let val_str = part.replace("BLADE_GE", "").replace("_", "");
            if let Ok(threshold) = val_str.parse::<i32>() {
                attr |= 0x02000000 | ((threshold as u64) << 25);
            }
        } else if part == "COST_LE_REVEALED" {
            // 公開されたカードのコスト制限
            attr |= 0x01000000 | (1u64 << 25);
            attr |= 0x40000000u64; // LE flag
            attr |= 1u64 << 43; // Bit 43: REVEALED context
        } else if part == "HEART_PINK" {
            attr |= 1u64 << 32; // Same as PINK
        } else if part == "HEART_BLUE" {
            attr |= 1u64 << 34; // Same as BLUE/COOL
        } else if part == "HASUNOSORA" {
            attr |= 0x10 | (4 << 5); // Group ID 4 for Hasunosora
        } else if part == "LIELLA" {
            attr |= 0x10 | (3 << 5); // Group ID 3 for Liella
        } else if part == "NIJIGASAKI" || part == "NIJIGAKU" {
            attr |= 0x10 | (2 << 5); // Group ID 2 for Nijigasaki
        }
    }
    attr
}


pub fn check_condition(state: &GameState, db: &CardDatabase, _p_idx: usize, cond: &Condition, ctx: &AbilityContext, depth: u32) -> bool {
    if depth > 10 { return false; }

    let mut val = cond.value;
    let mut attr = cond.attr;

    if let Some(params) = cond.params.as_object() {
        if val == 0 {
            if let Some(min) = params.get("min").and_then(|v| v.as_i64()) {
                val = min as i32;
            } else if let Some(min) = params.get("value").and_then(|v| v.as_i64()) {
                val = min as i32;
            } else if let Some(v) = params.get("val").and_then(|v| v.as_i64()) {
                val = v as i32;
            }
        }
        
        let mut mapped_attr = 0;
        if let Some(filter_str) = params.get("filter").and_then(|v| v.as_str()) {
            mapped_attr = map_filter_string_to_attr(filter_str);
        }
        
        if let Some(area_str) = params.get("area").and_then(|v| v.as_str()) {
            if area_str == "ANY_STAGE" || area_str == "ALL_AREAS" {
                mapped_attr |= 1u64 << 40; // Bit 40 for ANY_STAGE/ALL_AREAS
            }
        }
        
        if let Some(p_val) = params.get("player").and_then(|v| v.as_i64()) {
            if p_val == 2 { // Opponent
                mapped_attr |= 1u64 << 41; // Bit 41 for explicitly checking opponent
            }
        }

        if attr == 0 {
            attr = mapped_attr;
        } else {
            attr |= mapped_attr;
        }
    }

    if state.debug.debug_mode {
    }

    let result = if cond.condition_type != ConditionType::None {
        state.check_condition_opcode(db, cond.condition_type as i32, val, attr, 0, ctx, depth + 1)
    } else {
        true
    };

    let result = if cond.is_negated { !result } else { result };

    if !result && state.debug.debug_ignore_conditions {
        if let Ok(mut bypassed) = state.debug.bypassed_conditions.0.lock() {
            bypassed.push(format!("BYPASS Condition: Type {:?}, Value {}, Attr {}", cond.condition_type, cond.value, cond.attr));
        }
        return true;
    }
    result
}


pub fn get_choice_text(db: &CardDatabase, ctx: &AbilityContext) -> String {
    crate::core::logic::ActionFactory::get_choice_text(db, ctx)
}

pub fn suspend_interaction(state: &mut GameState, db: &CardDatabase, ctx: &AbilityContext, instr_ip: usize, effect_opcode: i32, target_slot: i32, choice_type: &str, choice_text: &str, filter_attr: u64, v_remaining: i16) -> bool {
    let mut p_ctx = ctx.clone();
    p_ctx.program_counter = instr_ip as u16; // Point EXACTLY at the current opcode
    p_ctx.choice_index = -1; 
    p_ctx.v_remaining = v_remaining;
    
    let original_cp = state.current_player;
    let original_phase = state.phase;

    state.interaction_stack.push(PendingInteraction {
        ctx: p_ctx,
        card_id: ctx.source_card_id,
        ability_index: ctx.ability_index,
        effect_opcode: effect_opcode,
        target_slot: target_slot,
        choice_type: choice_type.to_string(),
        filter_attr,
        choice_text: choice_text.to_string(),
        v_remaining,
        original_phase, // NOT prev_phase, but the ACTUAL phase it was in
        original_current_player: original_cp,
        ..Default::default()
    });
    state.phase = Phase::Response;
    // CRITICAL FIX: To allow proper resolution, temporarily treat the ability owner as current player
    // This allows generate_legal_actions to work for them.
    state.current_player = ctx.player_id;

    // SYSTEMIC FIX: Check if we just soft-locked by suspending for a choice with zero legal actions.
    let mut actions = Vec::with_capacity(8);
    state.generate_legal_actions(db, ctx.player_id as usize, &mut actions);
    
    // If only action 0 (Skip/Done) is available, it's effectively a soft-lock if the user expects more,
    // or just an empty choice that we should skip.
    // OPPONENT_CHOOSE is a special generic trigger that waits for frontend progression without explicit internal actions.
    if actions.len() <= 1 && (actions.is_empty() || actions.contains(&0)) && choice_type != "OPPONENT_CHOOSE" {
        if state.debug.debug_mode {
            println!("[DEBUG] Softlock prevented: {} has no legal actions. Skipping suspension.", choice_type);
        }
        state.interaction_stack.pop();
        state.phase = original_phase;
        state.current_player = original_cp;
        return false;
    }
    true
}

/// Resolves the effective slot index based on the opcode's target_slot and the current context.
/// Slot 4 often acts as a proxy for the 'Area Index' stored in the context.
pub fn resolve_target_slot(target_slot: i32, ctx: &AbilityContext) -> usize {
    if target_slot == 0 && ctx.target_slot >= 0 {
        return ctx.target_slot as usize;
    }
    if target_slot == 4 && ctx.area_idx >= 0 {
        ctx.area_idx as usize
    } else if target_slot == -1 || target_slot == 4 {
        // Fallback to 0 if we expect a slot but none is provided, or if slot 4 is passed without context
        if ctx.area_idx >= 0 { ctx.area_idx as usize } else { 0 }
    } else {
        target_slot.max(0) as usize
    }
}

pub fn check_condition_opcode(state: &GameState, db: &CardDatabase, op: i32, val: i32, attr: u64, slot: i32, ctx: &AbilityContext, depth: u32) -> bool {
    let p_idx = ctx.player_id as usize;
    let player = &state.core.players[p_idx];
    let opponent = &state.core.players[1 - p_idx];
    
    let get_cid = || {
        if ctx.source_card_id >= 0 { ctx.source_card_id }
        else if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 { player.stage[ctx.area_idx as usize] }
        else { -1 }
    };

    if state.debug.debug_mode {
        println!("[DEBUG] Condition Opcode: {}, Value: {}, Attr: {}, Slot: {}, Source: {:?}", op, val, attr, slot, get_cid());
    }

    let result = match op {
        C_TURN_1 => state.turn == 1,
        C_HAS_MEMBER => {
            let filter_attr = attr & 0x00000000FFFFFFFF;
            let check_self = (attr & (1u64 << 41)) == 0;
            let check_opp = (attr & (1u64 << 40)) != 0 || (attr & (1u64 << 41)) != 0;
            
            if check_self && player.stage.iter().filter(|&&id| id >= 0).any(|&id| {
                (id == val || id == (attr as i32)) || (filter_attr != 0 && state.card_matches_filter(db, id, filter_attr))
            }) { true }
            else if check_opp && opponent.stage.iter().filter(|&&id| id >= 0).any(|&id| {
                (id == val || id == (attr as i32)) || (filter_attr != 0 && state.card_matches_filter(db, id, filter_attr))
            }) { true }
            else { false }
        },
        C_HAS_COLOR => {
            let color_mask = (attr >> 32) & 0x7F;
            if color_mask != 0 {
                player.stage.iter().filter(|&&cid| cid >= 0).any(|&cid| {
                     if let Some(m) = db.get_member(cid) {
                         for i in 0..7 {
                             if (color_mask & (1 << i)) != 0 && m.hearts[i] > 0 { return true; }
                         }
                     }
                     false
                })
            } else {
                let color_idx = if attr != 0 { attr as usize } else { val as usize };
                if state.debug.debug_mode { println!("DEBUG [C_HAS_COLOR]: color_idx={}, stage={:?}", color_idx, player.stage); }
                if color_idx < 7 {
                    player.stage.iter().filter(|&&c| c >= 0).any(|&c| {
                         if let Some(m) = db.get_member(c) {
                             let has_heart = m.hearts[color_idx] > 0;
                             if state.debug.debug_mode { println!("DEBUG [C_HAS_COLOR]: cid={}, hearts={:?}, color_idx={}, result={}", c, m.hearts, color_idx, has_heart); }
                             has_heart
                         } else {
                             if state.debug.debug_mode { println!("DEBUG [C_HAS_COLOR]: cid={} NOT FOUND IN DB", c); }
                             false
                         }
                    })
                } else { false }
            }
        },
        C_COUNT_STAGE => {
            let filter_attr = attr & 0x00000000FFFFFFFF; 
            let include_opponent = (attr & (1u64 << 40)) != 0 || (attr & (1u64 << 41)) != 0;
            let only_opponent = (attr & (1u64 << 41)) != 0 && (attr & (1u64 << 40)) == 0;

            let mut ids = Vec::new();
            if !only_opponent { ids.extend(player.stage.iter().filter(|&&id| id >= 0)); }
            if include_opponent { ids.extend(opponent.stage.iter().filter(|&&id| id >= 0)); }

            let count = if (attr & 0x8000) != 0 { // UNIQUE_NAMES
                let mut names = std::collections::HashSet::new();
                for &&id in &ids {
                    if state.card_matches_filter(db, id, filter_attr) {
                        if let Some(m) = db.get_member(id) { names.insert(&m.name); }
                        else if let Some(l) = db.get_live(id) { names.insert(&l.name); }
                    }
                }
                names.len() as i32
            } else {
                ids.into_iter().filter(|&&id| state.card_matches_filter(db, id, filter_attr)).count() as i32
            };
            count >= val
        },
        C_IS_CENTER => ctx.area_idx == 1,
        C_COUNT_HAND => {
            let filter_attr = attr & 0x00000000FFFFFFFF;
            let count = if (attr & 0x8000) != 0 {
                let mut names = std::collections::HashSet::new();
                for &id in player.hand.iter().filter(|&&id| id >= 0) {
                    if state.card_matches_filter(db, id, filter_attr) {
                        if let Some(m) = db.get_member(id) { names.insert(&m.name); }
                    }
                }
                names.len() as i32
            } else {
                player.hand.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, filter_attr)).count() as i32
            };
            count >= val
        },
        C_COUNT_DISCARD => {
            let filter_attr = attr & 0x00000000FFFFFFFF;
            let count = if (attr & 0x8000) != 0 {
                let mut names = std::collections::HashSet::new();
                for &id in player.discard.iter().filter(|&&id| id >= 0) {
                    if state.card_matches_filter(db, id, filter_attr) {
                        if let Some(m) = db.get_member(id) { names.insert(&m.name); }
                    }
                }
                names.len() as i32
            } else {
                player.discard.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, filter_attr)).count() as i32
            };
            count >= val
        },
        C_COUNT_ENERGY => player.energy_zone.len() as i32 >= val,
        C_HAS_LIVE_CARD => player.live_zone.iter().any(|&cid| cid >= 0),
        COST_ENERGY => {
            let cost_delta = state.calculate_cost_delta(db, ctx.source_card_id, p_idx);
            let total_cost = (val + cost_delta).max(0);
            player.energy_zone.len() as i32 >= total_cost
        },
        COST_TAP_SELF => {
            let slot = resolve_target_slot(slot, ctx);
            slot < 3 && !player.is_tapped(slot)
        },
        COST_DISCARD_HAND => player.hand.len() as i32 >= val,
        COST_RETURN_HAND => player.stage.iter().filter(|&&id| id >= 0).count() as i32 >= val,
        COST_SACRIFICE_SELF => {
            let slot = resolve_target_slot(slot, ctx);
            slot < 3 && player.stage[slot] >= 0
        },
        COST_TAP_MEMBER => {
            player.stage.iter().enumerate().any(|(i, &cid)| cid >= 0 && !player.is_tapped(i))
        },
        COST_TAP_ENERGY => {
             (player.energy_zone.len() as u32 - player.tapped_energy_mask.count_ones()) as i32 >= val
        },
        COST_DISCARD_ENERGY => player.energy_zone.len() as i32 >= val,
        COST_PLACE_MEMBER_FROM_HAND => player.hand.len() as i32 >= val,
        C_RARITY_CHECK => {
             let cid = get_cid();
             if cid >= 0 {
                  db.get_member(cid).map_or(false, |m| m.rarity == val as u8)
             } else { false }
        },
        C_COUNT_SUCCESS_LIVE => {
            let filter_attr = attr & 0x00000000FFFFFFFF;
            let count = if (attr & 0x8000) != 0 {
                let mut names = std::collections::HashSet::new();
                for &id in player.success_lives.iter().filter(|&&id| id >= 0) {
                    if state.card_matches_filter(db, id, filter_attr) {
                        if let Some(m) = db.get_member(id) { names.insert(&m.name); }
                        else if let Some(l) = db.get_live(id) { names.insert(&l.name); }
                    }
                }
                names.len() as i32
            } else {
                player.success_lives.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, filter_attr)).count() as i32
            };
            count >= val
        },
        C_OPPONENT_HAS => {
             let filter_attr = attr & 0x00000000FFFFFFFF;
             opponent.stage.iter().filter(|&&id| id >= 0).any(|&cid| cid == val || (filter_attr != 0 && state.card_matches_filter(db, cid, filter_attr)))
        },
        C_LIFE_LEAD => {
            let my_lives = player.success_lives.len() as i32;
            let opp_lives = opponent.success_lives.len() as i32;
            (my_lives - opp_lives) >= val
        },
        C_COUNT_GROUP => {
            let filter_attr = attr & 0x00000000FFFFFFFF;
            player.stage.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, filter_attr)).count() as i32 >= val
        },
        C_GROUP_FILTER => {
            let lower_attr = attr & 0x00000000FFFFFFFF;
            let filter = if (lower_attr & 0x10) == 0 && lower_attr != 0 && lower_attr < 300 { 
                0x10 | (lower_attr << 5) 
            } else if (lower_attr & 0x10) == 0 && val != 0 {
                // val might contain flags in higher bits. Filter group ID is restricted to 7 bits (0-127).
                0x10 | (((val & 0x7F) as u64) << 5)
            } else { lower_attr };

            // Bit 2 of val (0x04) flags "Check ALL members on stage"
            if (val & 0x04) != 0 {
                player.stage.iter().filter(|&&cid| cid >= 0).all(|&cid| state.card_matches_filter(db, cid, filter))
            } else if let Some(cid) = state.get_context_card_id(ctx) {
                state.card_matches_filter(db, cid, filter)
            } else { false }
        },
        C_SELF_IS_GROUP => {
            let cid = if ctx.source_card_id >= 0 { ctx.source_card_id }
                      else if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 { player.stage[ctx.area_idx as usize] }
                      else { -1 };
            if cid >= 0 {
                let lower_attr = attr & 0x00000000FFFFFFFF;
                let filter = if (lower_attr & 0x10) == 0 && lower_attr != 0 && lower_attr < 300 { 
                    0x10 | (lower_attr << 5) 
                } else if (lower_attr & 0x10) == 0 && val != 0 {
                    0x10 | ((val as u64) << 5)
                } else { lower_attr };
                state.card_matches_filter(db, cid, filter)
            } else { false }
        },
        C_MODAL_ANSWER => ctx.choice_index == (val as i16),
        C_COST_CHECK => {
            if let Some(cid) = state.get_context_card_id(ctx) {
                if let Some(m) = db.get_member(cid) { m.cost as i32 >= val } else { false }
            } else { false }
        },
        C_HAND_HAS_NO_LIVE => {
            !player.hand.iter().filter(|&&id| id >= 0).any(|&id| db.get_live(id).is_some())
        },
        C_OPPONENT_HAND_DIFF => {
            let my_hand = player.hand.len() as i32;
            let opp_hand = opponent.hand.len() as i32;
            (opp_hand - my_hand) >= val
        },
        C_SCORE_COMPARE => {
            let my_score = player.score as i32;
            let target_score = if (attr & 0x20) != 0 { val } else { opponent.score as i32 };
            let op_type = (slot >> 4) & 0x0F;
            match op_type {
                0 => my_score >= target_score,
                1 => my_score <= target_score,
                2 => my_score > target_score,
                _ => my_score >= target_score,
            }
        },
        C_HAS_CHOICE => !state.interaction_stack.is_empty(),
        C_OPPONENT_CHOICE => state.interaction_stack.iter().any(|p| p.ctx.player_id != p_idx as u8),
        C_COUNT_HEARTS => {
            let mut total = 0;
            for i in 0..3 { total += state.get_effective_hearts(p_idx, i, db, depth + 1).get_total_count(); }
            total as i32 >= val
        },
        C_COUNT_BLADES => {
            let mut total = 0;
            for i in 0..3 { total += state.get_effective_blades(p_idx, i, db, depth + 1); }
            total as i32 >= val
        },
        C_OPPONENT_ENERGY_DIFF => {
            let my_energy = player.energy_zone.len() as i32;
            let opp_energy = opponent.energy_zone.len() as i32;
            (opp_energy - my_energy) >= val
        },
        C_HAS_KEYWORD => false,
        C_DECK_REFRESHED => player.get_flag(crate::core::logic::player::PlayerState::FLAG_DECK_REFRESHED),
        C_HAS_MOVED => ctx.area_idx >= 0 && player.is_moved(ctx.area_idx as usize),
        C_HAND_INCREASED => player.hand_increased_this_turn > 0,
        C_BATON => state.prev_card_id != -1 || player.baton_touch_count > 0,
        C_COUNT_LIVE_ZONE => {
             let filter_attr = attr & 0x00000000FFFFFFFF;
             let count = if (attr & 0x8000) != 0 {
                let mut names = std::collections::HashSet::new();
                for &id in player.live_zone.iter().filter(|&&id| id >= 0) {
                    if state.card_matches_filter(db, id, filter_attr) {
                        if let Some(l) = db.get_live(id) { names.insert(&l.name); }
                    }
                }
                names.len() as i32
             } else {
                player.live_zone.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, filter_attr)).count() as i32
             };
             count >= val
        },
        C_TYPE_CHECK => {
            let check_val = if val == 0 && (attr & 0x00000000FFFFFFFF) != 0 { (attr & 0x00000000FFFFFFFF) as i32 } else { val };
            if let Some(card_id) = state.get_context_card_id(ctx) {
                if check_val == 1 { db.get_live(card_id).is_some() }
                else { db.get_member(card_id).is_some() }
            } else { false }
        },
        C_IS_IN_DISCARD => {
            let cid = ctx.source_card_id;
            if cid >= 0 { player.discard.contains(&(cid as i32)) } else { false }
        },
        C_AREA_CHECK => ctx.area_idx == (val - 1) as i16,
        C_COST_LEAD => {
            // 自分の場のコスト合計 vs 相手
            let self_cost: i32 = player.stage.iter()
                .filter(|&&id| id >= 0)
                .map(|&id| db.get_member(id).map_or(0, |m| m.cost as i32))
                .sum();
            let opp_cost: i32 = opponent.stage.iter()
                .filter(|&&id| id >= 0)
                .map(|&id| db.get_member(id).map_or(0, |m| m.cost as i32))
                .sum();
            let reversed = (attr & 0x01) != 0;
            if reversed { opp_cost > self_cost } else { self_cost > opp_cost }
        },
        C_SCORE_LEAD => {
            let self_score = player.score as i32;
            let opp_score = opponent.score as i32;
            let reversed = (attr & 0x01) != 0;
            if reversed { opp_score > self_score } else { self_score > opp_score }
        },
        C_HEART_LEAD => {
            let self_hearts = state.get_total_hearts(p_idx, db, depth + 1);
            let opp_hearts = state.get_total_hearts(1 - p_idx, db, depth + 1);
            let self_total = self_hearts.to_array().iter().map(|&x| x as i32).sum::<i32>();
            let opp_total = opp_hearts.to_array().iter().map(|&x| x as i32).sum::<i32>();
            let reversed = (attr & 0x01) != 0;
            if reversed { opp_total > self_total } else { self_total > opp_total }
        },
        C_HAS_EXCESS_HEART => {
            // ライブ成功後の余剰ハートチェック
            player.excess_hearts > 0
        },
        C_NOT_HAS_EXCESS_HEART => {
            player.excess_hearts == 0
        },
        C_TOTAL_BLADES => {
            let total = state.get_total_blades(p_idx, db, depth + 1);
            total >= val as u32
        },
        C_COST_COMPARE => {
            let cid = if ctx.source_card_id >= 0 { ctx.source_card_id }
                      else if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 { player.stage[ctx.area_idx as usize] }
                      else { -1 };
            if cid >= 0 {
                if let Some(m) = db.get_member(cid) {
                    let threshold = val;
                    let is_le = (attr & 0x40000000) != 0;
                    if is_le { m.cost as i32 <= threshold } else { m.cost as i32 >= threshold }
                } else { false }
            } else { false }
        },
        C_BLADE_COMPARE => {
            let slot = if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 { ctx.area_idx as usize } else { 0 };
            let blades = state.get_effective_blades(p_idx, slot, db, depth + 1);
            let threshold = val as u32;
            let is_le = (attr & 0x40000000) != 0;
            if is_le { blades <= threshold } else { blades >= threshold }
        },
        C_HEART_COMPARE => {
            let slot = if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 { ctx.area_idx as usize } else { 0 };
            let hearts = state.get_effective_hearts(p_idx, slot, db, depth + 1);
            let color_idx = (attr & 0x7F) as usize;
            let count = if color_idx < 7 { hearts.to_array()[color_idx] as i32 } else { hearts.get_total_count() as i32 };
            let threshold = val;
            let is_le = (attr & 0x40000000) != 0;
            if is_le { count <= threshold } else { count >= threshold }
        },
        C_OPPONENT_HAS_WAIT => {
            // 相手の場にWAIT（タップ状態）のメンバーがいるか
            (0..3).any(|i| opponent.stage[i] >= 0 && opponent.is_tapped(i))
        },
        _ => {
            false
        }
    };

    if !result && state.debug.debug_ignore_conditions {
        if let Ok(mut bypassed) = state.debug.bypassed_conditions.0.lock() {
            bypassed.push(format!("BYPASS Opcode: {}, Value {}, Attr {}", op, val, attr));
        }
        return true;
    }
    if state.debug.debug_mode {
        println!("[DEBUG] Condition Result: {} (Negated: {})", result, state.debug.debug_ignore_conditions);
    }
    result
}





pub fn check_cost(state: &GameState, db: &CardDatabase, p_idx: usize, cost: &Cost, ctx: &AbilityContext) -> bool {
    let player = &state.core.players[p_idx];
    let val = cost.value as usize;
    let mut attr: u64 = 0;
    if let Some(params) = cost.params.as_object() {
        if let Some(filter_str) = params.get("filter").and_then(|v| v.as_str()) {
            attr = map_filter_string_to_attr(filter_str);
        }
    }
     let result = match cost.cost_type {
         AbilityCostType::None => true,
         AbilityCostType::Energy => {
              let available = (0..player.energy_zone.len()).filter(|&i| !player.is_energy_tapped(i)).count() as i32;
              available >= cost.value
         },
         AbilityCostType::TapSelf => {
              if ctx.area_idx >= 0 {
                  !player.is_tapped(ctx.area_idx as usize)
              } else { false }
         },
         AbilityCostType::TapMember => {
            if val == 0 {
                // FALLBACK: TapMember(0) refers to self (Wait self) - used by some Activated patterns
                if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                    player.stage[ctx.area_idx as usize] >= 0 && !player.is_tapped(ctx.area_idx as usize)
                } else { false }
            } else {
                let untapped_count = (0..3).filter(|&i| player.stage[i] >= 0 && !player.is_tapped(i)).count();
                untapped_count >= val
            }
        },
        AbilityCostType::TapEnergy => {
            let untapped_energy = (0..player.energy_zone.len()).filter(|&i| !player.is_energy_tapped(i)).count();
            untapped_energy >= val
        },
         AbilityCostType::DiscardHand => {
             if attr != 0 {
                 player.hand.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, attr)).count() >= val
             } else {
                 player.hand.len() >= val
             }
         },
         AbilityCostType::SacrificeSelf => {
             if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                 player.stage[ctx.area_idx as usize] >= 0
             } else { false }
         },
         AbilityCostType::RevealHand => {
             player.hand.len() >= val
         },
         AbilityCostType::SacrificeUnder => {
             if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                 player.stage_energy[ctx.area_idx as usize].len() >= val
             } else { false }
         },
         AbilityCostType::DiscardEnergy => {
             player.energy_zone.len() >= val
         },
         AbilityCostType::ReturnMemberToDeck => {
             if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                 player.stage[ctx.area_idx as usize] >= 0
             } else { false }
         },
         AbilityCostType::ReturnDiscardToDeck => {
             player.discard.len() >= val
         },
         AbilityCostType::ReturnHand => {
             if attr != 0 {
                 player.stage.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, attr)).count() >= val
             } else {
                 player.stage.iter().filter(|&&id| id >= 0).count() >= val
             }
         },
         AbilityCostType::DiscardMember => {
             if attr != 0 {
                 player.stage.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, attr)).count() >= val
             } else {
                 player.stage.iter().filter(|&&id| id >= 0).count() >= val
             }
         },
         AbilityCostType::DiscardSuccessLive => {
             if attr != 0 {
                 player.success_lives.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, attr)).count() >= val
             } else {
                 player.success_lives.len() >= val
             }
         },
         _ => true
     };

    if !result && state.debug.debug_ignore_conditions {
        if let Ok(mut bypassed) = state.debug.bypassed_conditions.0.lock() {
            bypassed.push(format!("BYPASS Cost: Type {:?}, Value {}", cost.cost_type, cost.value));
        }
        return true;
    }
    result
}

pub fn pay_cost(state: &mut GameState, db: &CardDatabase, p_idx: usize, cost: &Cost, ctx: &AbilityContext) -> bool {
    let mut attr = 0;
    if let Some(params) = cost.params.as_object() {
        if let Some(filter_str) = params.get("filter").and_then(|v| v.as_str()) {
            attr = map_filter_string_to_attr(filter_str);
        }
    }

    if state.debug.debug_mode {
        println!("[DEBUG] Paying Cost: {:?}, Value: {}, Card: {}", cost.cost_type, cost.value, ctx.source_card_id);
    }
    let result = match cost.cost_type {
        AbilityCostType::None => true,
        AbilityCostType::Energy => {
            let untap_indices: Vec<usize> = (0..state.core.players[p_idx].energy_zone.len())
                .filter(|&i| !state.core.players[p_idx].is_energy_tapped(i))
                .take(cost.value as usize).collect();
            if untap_indices.len() < cost.value as usize { return false; }
            for idx in untap_indices { state.core.players[p_idx].set_energy_tapped(idx, true); }
            true
        }
        AbilityCostType::TapSelf => {
            if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                state.core.players[p_idx].set_tapped(ctx.area_idx as usize, true);
                true
            } else { false }
        },
        AbilityCostType::TapMember => {
            let player = &mut state.core.players[p_idx];
            let mut needed = cost.value as usize;
            if needed == 0 { 
                // FALLBACK: Value 0 means "Tap Self"
                if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                    player.set_tapped(ctx.area_idx as usize, true);
                    return true;
                }
                return false;
            }
            for i in 0..3 {
                if !player.is_tapped(i) && player.stage[i] >= 0 {
                    player.set_tapped(i, true);
                    needed -= 1;
                    if needed == 0 { break; }
                }
            }
            needed == 0
        },
        AbilityCostType::TapEnergy => {
            let player = &mut state.core.players[p_idx];
            let mut needed = cost.value as usize;
            if needed == 0 { return true; }
            for i in 0..player.energy_zone.len() {
                if !player.is_energy_tapped(i) {
                    player.set_energy_tapped(i, true);
                    needed -= 1;
                    if needed == 0 { break; }
                }
            }
            needed == 0
        },
        AbilityCostType::DiscardHand => {
            let count = cost.value as usize;
            let filter_attr = attr;
            
            if filter_attr != 0 {
                let mut to_discard = Vec::new();
                for &cid in &state.core.players[p_idx].hand {
                    if state.card_matches_filter(db, cid, filter_attr) {
                        to_discard.push(cid);
                        if to_discard.len() >= count { break; }
                    }
                }
                
                if to_discard.len() < count { return false; }
                
                for cid in to_discard {
                    if let Some(pos) = state.core.players[p_idx].hand.iter().position(|&x| x == cid) {
                        state.core.players[p_idx].hand.remove(pos);
                        state.core.players[p_idx].discard.push(cid);
                    }
                }
                true
            } else {
                let player = &mut state.core.players[p_idx];
                if player.hand.len() < count { return false; }
                for _ in 0..count {
                    if let Some(cid) = player.hand.pop() {
                        player.discard.push(cid);
                    }
                }
                true
            }
        },
        AbilityCostType::SacrificeSelf => {
            if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                let slot = ctx.area_idx as usize;
                let cid = state.core.players[p_idx].stage[slot];
                if cid >= 0 {
                    let mut leave_ctx = ctx.clone();
                    leave_ctx.source_card_id = cid;
                    leave_ctx.area_idx = ctx.area_idx;
                    state.trigger_abilities(db, TriggerType::OnLeaves, &leave_ctx);

                    let player = &mut state.core.players[p_idx];
                    player.stage[slot] = -1;
                    player.discard.push(cid as i32);
                    let under_cards = std::mem::take(&mut player.stage_energy[slot]);
                    player.discard.extend(under_cards);
                    player.stage_energy_count[slot] = 0;
                    true
                } else { false }
            } else { false }
        },
        AbilityCostType::RevealHand => true,
        AbilityCostType::SacrificeUnder => {
            if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                let player = &mut state.core.players[p_idx];
                let count = cost.value as usize;
                let slot = ctx.area_idx as usize;
                if player.stage_energy[slot].len() < count { return false; }
                for _ in 0..count {
                    if let Some(cid) = player.stage_energy[slot].pop() {
                        player.discard.push(cid);
                    }
                }
                player.stage_energy_count[slot] = player.stage_energy[slot].len() as u8;
                true
            } else { false }
        },
        AbilityCostType::DiscardEnergy => {
            let player = &mut state.core.players[p_idx];
            let count = cost.value as usize;
            if player.energy_zone.len() < count { return false; }
            for _ in 0..count {
                if let Some(cid) = player.energy_zone.pop() {
                    // tapped_energy_mask doesn't strictly need popping, 
                    // but we should ensure bit is clear if we reuse index
                    // Actually, energy_zone.len() handles the bounds.
                    player.discard.push(cid);
                }
            }
            true
        },
        AbilityCostType::ReturnMemberToDeck => {
             if ctx.area_idx >= 0 && (ctx.area_idx as usize) < 3 {
                 let slot = ctx.area_idx as usize;
                 let cid = state.core.players[p_idx].stage[slot];
                 if cid >= 0 {
                     let mut leave_ctx = ctx.clone();
                     leave_ctx.source_card_id = cid;
                     leave_ctx.area_idx = slot as i16;
                     state.trigger_abilities(db, TriggerType::OnLeaves, &leave_ctx);

                     let player = &mut state.core.players[p_idx];
                     player.stage[slot] = -1;
                     player.deck.insert(0, cid as i32);
                     true
                 } else { false }
             } else { false }
        },
        AbilityCostType::ReturnDiscardToDeck => {
            let player = &mut state.core.players[p_idx];
            let count = cost.value as usize;
            if player.discard.len() < count { return false; }
            for _ in 0..count {
                if let Some(cid) = player.discard.pop() {
                    player.deck.push(cid);
                }
            }
            true
        },
        AbilityCostType::ReturnHand | AbilityCostType::DiscardMember | AbilityCostType::ReturnMemberToHand | AbilityCostType::ReturnMemberToDiscard => {
            let count = cost.value as usize;
            let filter_attr = attr;
            let is_discard = cost.cost_type == AbilityCostType::DiscardMember;
            let mut slots_to_move = Vec::new();
            for i in 0..3 {
                let cid = state.core.players[p_idx].stage[i];
                if cid >= 0 && (filter_attr == 0 || state.card_matches_filter(db, cid, filter_attr)) {
                    slots_to_move.push(i);
                    if slots_to_move.len() >= count { break; }
                }
            }
            if slots_to_move.len() < count { return false; }
            for slot in slots_to_move {
                if let Some(old) = state.handle_member_leaves_stage(p_idx, slot, db, ctx) {
                    if is_discard { state.core.players[p_idx].discard.push(old); }
                    else { state.core.players[p_idx].hand.push(old); }
                }
            }
            true
        },
        AbilityCostType::DiscardSuccessLive => {
            let count = cost.value as usize;
            let filter_attr = attr as i32;
            let mut indices = Vec::new();
            for (idx, &cid) in state.core.players[p_idx].success_lives.iter().enumerate() {
                if filter_attr == 0 || state.card_matches_filter(db, cid, filter_attr as u64) {
                    indices.push(idx);
                    if indices.len() >= count { break; }
                }
            }
            if indices.len() < count { return false; }
            for &idx in indices.iter().rev() {
                let cid = state.core.players[p_idx].success_lives.remove(idx);
                state.core.players[p_idx].discard.push(cid);
            }
            true
        },
        _ => false,
    };
    if !result && state.debug.debug_ignore_conditions {
        return true;
    }
    if state.debug.debug_mode && !result {
        println!("[DEBUG] Cost Payment FAILED");
    }
    result
}

pub fn get_condition_count(state: &GameState, db: &CardDatabase, cond_id: i32, attr: i32, ctx: &AbilityContext) -> i32 {
    let p_idx = ctx.player_id as usize;
    let player = &state.core.players[p_idx];
    let opponent = &state.core.players[1 - p_idx];
    let filter_attr = attr & !0x03;
    let include_opponent = (attr & 0x01) != 0 || (attr & 0x02) != 0;
    let only_opponent = (attr & 0x02) != 0 && (attr & 0x01) == 0;

    let get_zone_count = |ids: &[i32]| {
        if (attr & 0x8000) != 0 {
             let mut names = std::collections::HashSet::new();
             for &id in ids {
                 if id >= 0 && state.card_matches_filter(db, id, filter_attr as u64) {
                     if let Some(m) = db.get_member(id) { names.insert(&m.name); }
                     else if let Some(l) = db.get_live(id) { names.insert(&l.name); }
                 }
             }
             names.len() as i32
        } else {
             ids.iter().filter(|&&id| id >= 0 && state.card_matches_filter(db, id, filter_attr as u64)).count() as i32
        }
    };

    match cond_id {
        203 => { // COUNT_STAGE
             let mut count = 0;
             if !only_opponent { count += get_zone_count(&player.stage); }
             if include_opponent { count += get_zone_count(&opponent.stage); }
             count
        },
        204 => get_zone_count(&player.hand), // COUNT_HAND
        205 => get_zone_count(&player.discard), // COUNT_DISCARD
        213 => player.energy_zone.len() as i32, // COUNT_ENERGY
        218 => get_zone_count(&player.success_lives), // COUNT_SUCCESS_LIVE
        223 => { // COUNT_HEARTS
            let totals = state.get_total_hearts(p_idx, db, 0);
            if attr == 0 {
                totals.to_array().iter().map(|&x| x as u32).sum::<u32>() as i32
            } else {
                let color_idx = (attr as usize).saturating_sub(1);
                if color_idx < 7 {
                    totals.get_color_count(color_idx) as i32 + totals.to_array()[6] as i32
                } else { 0 }
            }
        },
        224 => state.get_total_blades(p_idx, db, 0) as i32, // COUNT_BLADES
        230 => get_zone_count(&player.live_zone), // COUNT_LIVE_ZONE
        _ => 0,
    }
}

pub fn resolve_bytecode(state: &mut GameState, db: &CardDatabase, bytecode: &[i32], ctx_in: &AbilityContext) {
    if ctx_in.program_counter != 0 {
        // Resumption: phase was already restored by the caller (activate_ability_with_choice)
        // Do NOT force Phase::Main here — the caller handles phase restoration.
    }
    const MAX_DEPTH: usize = 8;
    let mut stack: [(&[i32], usize, AbilityContext); MAX_DEPTH] = [(&[], 0, AbilityContext::default()); MAX_DEPTH];
    let mut sp = 0;

    stack[sp] = (bytecode, ctx_in.program_counter as usize, *ctx_in);
    sp += 1;

    let mut cond = true;
    let mut steps = 0;

    while sp > 0 {
        sp -= 1;
        let (cur_bc, mut ip, mut ctx) = stack[sp];
        let len = cur_bc.len();

        while ip < len && steps < 1000 {
            steps += 1;
            let instr_ip = ip;
            let op = cur_bc[ip];

            // Safe reading for the standard 3-parameter format
            let v = if ip + 1 < len { cur_bc[ip+1] } else { 0 };
            let a = if ip + 2 < len { cur_bc[ip+2] } else { 0 };
            let s = if ip + 3 < len { cur_bc[ip+3] } else { 0 };

            let instr_len = 4;
            ip += instr_len;
            ctx.program_counter = instr_ip as u16;
            
            // Resumption Check: If we are starting from a suspended IP, inject the choice_index
             if instr_ip == ctx_in.program_counter as usize && ctx_in.choice_index != -1 {
                 ctx.choice_index = ctx_in.choice_index;
             } 
             // IMPORTANT: Do NOT reset choice_index to -1 here, 
             // because it might be a resumed choice for the very first opcode.
             // We will reset it at the end of each opcode processing iteration instead.

            if op == O_NOP as i32 { continue; }
            if op == O_RETURN as i32 { 
                break; 
            }

            let mut is_negated = false;
            let mut real_op = op;
            if real_op >= 1000 {
                is_negated = true;
                real_op -= 1000;
            }

            if state.debug.debug_mode {
                println!("[DEBUG] BC_STEP: ip={}, op={}, v={}, a={}, s={}, cond={}", instr_ip, real_op, v, a, s, cond);
            }

            let mut target_slot = s & 0xFF;
            if target_slot == 10 { target_slot = ctx.target_slot as i32; }

            if real_op >= 200 && real_op <= 255 {
                let passed = state.check_condition_opcode(db, real_op, v, a as u64, target_slot, &ctx, 0);
                cond = cond && if is_negated { !passed } else { passed };
                continue;
            }

            if real_op == O_JUMP as i32 {
                ip += v as usize * 4;
                continue;
            }
            if real_op == O_JUMP_IF_FALSE as i32 {
                if !cond {
                    ip += v as usize * 4;
                }
                continue;
            }

            if real_op == O_SELECT_MODE as i32 {
                match handle_select_mode(state, db, &mut ctx, v, a, s, instr_ip, &cur_bc) {
                    Some(new_ip) => {
                        ip = new_ip;
                        // Propagate choice for color-selective modes
                        if v == 6 {
                             ctx.selected_color = ctx.choice_index;
                        }
                        ctx.choice_index = -1; // Reset choice for mode selection branch
                        if state.phase == Phase::Response { return; }
                        continue;
                    },
                    None => return, // Suspended
                }
            }

            if state.debug.debug_mode {
                println!("[DEBUG COND_GATE] ip={}, op={}, cond={}, choice_index={}", instr_ip, real_op, cond, ctx.choice_index);
            }
            if cond {
                let p_idx = ctx.player_id as usize;
                
                // Resolve Dynamic Value (Flag 64)
                let final_v = if (a & 64) != 0 {
                    get_condition_count(state, db, v, a & !64, &ctx)
                } else {
                    v
                };

                match real_op {
                    O_DRAW => {
                        let count = final_v as u32;
                        if state.debug.debug_mode {
                            println!("[DEBUG] ZONE MOVE: DRAW. Player {} -> Hand (Count: {})", p_idx, count);
                        }
                        if target_slot == 2 { state.draw_cards(1 - p_idx, count); }
                        else if target_slot == 3 { state.draw_cards(0, count); state.draw_cards(1, count); }
                        else { state.draw_cards(p_idx, count); }
                        state.log_turn_event("EFFECT", ctx.source_card_id, ctx.ability_index, p_idx as u8, &format!("Draw {} card(s)", count));
                    },
                    O_RECOVER_LIVE | O_RECOVER_MEMBER => {
                        match handle_recovery(state, db, &mut ctx, v, a, s, instr_ip, real_op) {
                            Some(c) => cond = c,
                            None => return,
                        }
                    },
                    O_BOOST_SCORE => state.core.players[p_idx].live_score_bonus += final_v,
                    O_ENERGY_CHARGE => {
                        let target_p = if s == 2 { 1 - p_idx } else { p_idx };
                        let is_wait = (a & 0x01) != 0;
                        for _ in 0..final_v {
                            if let Some(cid) = state.core.players[target_p].energy_deck.pop() {
                                state.core.players[target_p].energy_zone.push(cid);
                                let new_idx = state.core.players[target_p].energy_zone.len() - 1;
                                state.core.players[target_p].set_energy_tapped(new_idx, is_wait);
                            }
                        }
                    },
                    O_ADD_TO_HAND => {
                        if s == 90 || s == 6 { 
                             let count = v as usize;
                             for _ in 0..count {
                                 if !state.core.players[p_idx].looked_cards.is_empty() {
                                     let cid = state.core.players[p_idx].looked_cards.remove(0);
                                     state.core.players[p_idx].hand.push(cid);
                                     state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
                                 }
                             }
                        } else {
                            state.draw_cards(p_idx, final_v as u32)
                        }
                    },
                    O_DRAW_UNTIL => {
                        let target_hand_size = final_v as usize;
                        let current_hand_size = state.core.players[p_idx].hand.len();
                        if current_hand_size < target_hand_size {
                            let to_draw = (target_hand_size - current_hand_size) as u32;
                            state.draw_cards(p_idx, to_draw);
                        }
                    },
                    O_PAY_ENERGY => {
                        let available = (0..state.core.players[p_idx].energy_zone.len())
                            .filter(|&i| !state.core.players[p_idx].is_energy_tapped(i))
                            .count() as i32;

                        if (a & 0x82) != 0 && ctx.choice_index == -1 {
                            if available < final_v {
                                cond = false;
                            } else {
                                if !suspend_interaction(state, db, &ctx, instr_ip, O_PAY_ENERGY, 0, "OPTIONAL", "", a as u64, -1) { continue; }
                                return;
                            }
                        }
                        
                        let mut next_ctx = ctx.clone();
                        if (a & 0x82) != 0 && ctx.choice_index != -1 && ctx.v_remaining == -1 {
                             if ctx.choice_index == 1 { cond = false; }
                             next_ctx.choice_index = -1; // Consume the YES/NO
                             next_ctx.v_remaining = v as i16;
                        }
                        
                        if cond { // Only if not declined
                            if next_ctx.choice_index == 99 {
                                cond = false;
                            } else if available < final_v {
                                cond = false;
                            } else {
                                if next_ctx.choice_index == -1 && final_v > 0 && available > final_v && !state.ui.silent {
                                     // Fully automated: Always auto-pay even if multiple combinations exist.
                                     // This reduces "click fatigue" for abilities with cost 2+.
                                }
                                
                                 if next_ctx.choice_index != -1 {
                                    let idx = next_ctx.choice_index as usize;
                                    if idx < state.core.players[p_idx].energy_zone.len() {
                                        if !state.core.players[p_idx].is_energy_tapped(idx) {
                                            state.core.players[p_idx].set_energy_tapped(idx, true);
                                            next_ctx.v_remaining -= 1;
                                        }
                                        if next_ctx.v_remaining > 0 {
                                            next_ctx.choice_index = -1;
                                            if !suspend_interaction(state, db, &next_ctx, instr_ip, O_PAY_ENERGY, 0, "PAY_ENERGY", "", 0, next_ctx.v_remaining) { continue; }
                                            return;
                                        }
                                    }
                                } else {
                                    // Auto-pay (Silent or exact amount)
                                    let mut paid = 0;
                                    let player = &mut state.core.players[p_idx];
                                    for i in 0..player.energy_zone.len() {
                                        if paid >= final_v { break; }
                                        if !player.is_energy_tapped(i) {
                                            player.set_energy_tapped(i, true);
                                            paid += 1;
                                        }
                                    }
                                }
                                cond = true;
                            }
                        }
                    },
                    O_ACTIVATE_MEMBER => {
                         let slot = resolve_target_slot(target_slot, &ctx);
                         if target_slot == 1 {
                             for i in 0..3 { state.core.players[p_idx].set_tapped(i, false); }
                         } else if slot < 3 {
                             state.core.players[p_idx].set_tapped(slot, false);
                         }
                    },
                    O_ACTIVATE_ENERGY => {
                         let mut count = 0;
                         for i in 0..state.core.players[p_idx].energy_zone.len() {
                             if count >= final_v { break; }
                             if state.core.players[p_idx].is_energy_tapped(i) {
                                 state.core.players[p_idx].set_energy_tapped(i, false);
                                 count += 1;
                             }
                         }
                    },
                    O_REDUCE_YELL_COUNT => { state.core.players[p_idx].yell_count_reduction = final_v as i16; },
                    O_NEGATE_EFFECT => {
                        let trigger_type = match v {
                            1 => TriggerType::OnPlay, 2 => TriggerType::OnLiveStart, 3 => TriggerType::OnLiveSuccess,
                            4 => TriggerType::TurnStart, 5 => TriggerType::TurnEnd, 6 => TriggerType::Constant,
                            7 => TriggerType::Activated, 8 => TriggerType::OnLeaves, 9 => TriggerType::OnReveal,
                            10 => TriggerType::OnPositionChange, _ => TriggerType::None,
                        };
                        if target_slot >= 0 && (target_slot as usize) < 3 {
                            let cid = state.core.players[p_idx].stage[target_slot as usize];
                            if cid >= 0 {
                                state.core.players[p_idx].negated_triggers.push((cid, trigger_type, a.max(1) as i32));
                            }
                        }
                    },
                    O_SWAP_AREA => {
                         let p = &mut state.core.players[p_idx];
                         let temp_stage = p.stage;
                         let temp_energy = p.stage_energy_count;
                         let temp_tapped = [p.is_tapped(0), p.is_tapped(1), p.is_tapped(2)];
                         let temp_moved = [p.is_moved(0), p.is_moved(1), p.is_moved(2)];
                         if v == 2 || (a == 1 && s == 0) {
                             let src = ctx.area_idx as usize;
                             let dst = a as usize;
                             if src < 3 && dst < 3 {
                                p.stage[src] = temp_stage[dst]; p.stage[dst] = temp_stage[src];
                                p.stage_energy_count[src] = temp_energy[dst]; p.stage_energy_count[dst] = temp_energy[src];
                                p.set_tapped(src, temp_tapped[dst]); p.set_tapped(dst, temp_tapped[src]);
                                p.set_moved(src, temp_moved[dst]); p.set_moved(dst, temp_moved[src]);
                             }
                         } else {
                             p.stage[0] = temp_stage[2]; p.stage[1] = temp_stage[0]; p.stage[2] = temp_stage[1];
                             p.stage_energy_count[0] = temp_energy[2]; p.stage_energy_count[1] = temp_energy[0]; p.stage_energy_count[2] = temp_energy[1];
                             p.set_tapped(0, temp_tapped[2]); p.set_tapped(1, temp_tapped[0]); p.set_tapped(2, temp_tapped[1]);
                             p.set_moved(0, temp_moved[2]); p.set_moved(1, temp_moved[0]); p.set_moved(2, temp_moved[1]);
                         }
                     },
                    O_SWAP_ZONE => {
                        if let Some(res) = handle_swap_zone(state, db, &mut ctx, v, a, s, instr_ip) {
                            if !res { return; }
                        } else {
                            return;
                        }
                    },
                    O_RESTRICTION => {
                        let p_idx = ctx.player_id as usize;
                        state.core.players[p_idx].restrictions.push(a as u8);
                        if a == 1 { // Convention: 1 = cannot_live
                            state.core.players[p_idx].set_flag(crate::core::logic::player::PlayerState::FLAG_CANNOT_LIVE, true);
                        }
                    },
                    O_TRANSFORM_HEART => {
                        let p_idx = ctx.player_id as usize;
                        let src = a as usize;
                        let dst = s as usize;
                        if src < 7 && dst < 7 {
                            let amt = v.abs();
                            if state.core.players[p_idx].heart_req_reductions.get_color_count(src) >= amt as u8 {
                                state.core.players[p_idx].heart_req_reductions.add_to_color(src, -(amt as i32));
                                state.core.players[p_idx].heart_req_reductions.add_to_color(dst, amt as i32);
                            }
                        }
                    },
                    O_REDUCE_LIVE_SET_LIMIT => {
                        let p_idx = ctx.player_id as usize;
                        state.core.players[p_idx].prevent_success_pile_set = state.core.players[p_idx].prevent_success_pile_set.saturating_add(v as u8);
                    },
                    O_FLAVOR | O_REPLACE_EFFECT | O_MODIFY_SCORE_RULE | O_ADD_CONTINUOUS => {
                        // Metadata or internal opcodes that don't affect core logic yet
                    },
                    O_SET_HEART_COST => {
                        if !state.ui.silent { state.log(format!("O_SET_HEART_COST triggered with final_v={:x}. (Not yet globally supported)", final_v)); }
                    },
                    O_INCREASE_HEART_COST => {
                         if (s as usize) < 7 {
                             state.core.players[p_idx].heart_req_additions.add_to_color(s as usize, final_v);
                         }
                    },
                    O_ADD_BLADES | O_BUFF_POWER => {
                        let slot = resolve_target_slot(target_slot, &ctx);
                        if target_slot == 1 {
                            for t in 0..3 { state.core.players[p_idx].blade_buffs[t] += final_v as i16; }
                        } else if slot < 3 {
                            state.core.players[p_idx].blade_buffs[slot] += final_v as i16;
                        }
                        state.log_turn_event("EFFECT", ctx.source_card_id, ctx.ability_index, p_idx as u8, &format!("+{} Appeal", final_v));
                    },
                    O_GRANT_ABILITY => {
                        let ab_idx = v as u16;
                        let source_cid = ctx.source_card_id;
                        let mut targets = smallvec::SmallVec::<[i32; 3]>::new();
                        let slot = resolve_target_slot(target_slot, &ctx);
                        if target_slot == 4 && slot < 3 {
                            let cid = state.core.players[p_idx].stage[slot];
                            if cid >= 0 { targets.push(cid); }
                        } else if target_slot == 1 {
                            for i in 0..3 {
                                let cid = state.core.players[p_idx].stage[i];
                                if cid >= 0 { targets.push(cid); }
                            }
                        } else if target_slot >= 0 && target_slot < 3 {
                             let cid = state.core.players[p_idx].stage[target_slot as usize];
                             if cid >= 0 { targets.push(cid); }
                        }
                        
                        for t_cid in targets {
                            state.core.players[p_idx].granted_abilities.push((t_cid, source_cid, ab_idx));
                        }
                    },
                    O_ADD_HEARTS => {
                        let mut color = a as usize;
                        if color == 0 { color = ctx.selected_color as usize; }
                        if color < 7 {
                            if (target_slot == 4 || target_slot == 0) && ctx.area_idx >= 0 {
                                state.core.players[p_idx].heart_buffs[ctx.area_idx as usize].add_to_color(color, v as i32);
                            } else if target_slot == 1 {
                                for t in 0..3 { state.core.players[p_idx].heart_buffs[t].add_to_color(color, v as i32); }
                            } else {
                            }
                        } else {
                        }
                        state.log_turn_event("EFFECT", ctx.source_card_id, ctx.ability_index, p_idx as u8, &format!("+{} Heart(s)", v));
                    },
                    O_COLOR_SELECT => {
                        if ctx.choice_index == -1 {
                            let choice_text = get_choice_text(db, &ctx);
                            if !suspend_interaction(state, db, &ctx, instr_ip, O_COLOR_SELECT, 0, "COLOR_SELECT", &choice_text, 0, -1) { continue; }
                            return;
                        } else {
                            ctx.selected_color = ctx.choice_index;
                        }
                        ctx.choice_index = -1; // FIXED
                    },
                    O_REDUCE_COST => state.core.players[p_idx].cost_reduction += v as i16,
                    O_SET_BLADES => {
                         if target_slot == 4 && ctx.area_idx >= 0 {
                             state.core.players[p_idx].blade_buffs[ctx.area_idx as usize] = v as i16;
                         }
                    },
                    O_TAP_OPPONENT => {
                        if ctx.choice_index == -1 {
                            let choice_text = get_choice_text(db, &ctx);
                            if !suspend_interaction(state, db, &ctx, instr_ip, O_TAP_OPPONENT, 0, "TAP_O", &choice_text, 0, -1) { continue; }
                            return;
                        }
                        // Resumed: TAP_M/TAP_O choices are usually stage slots (0, 1, 2).
                        let slot_idx = ctx.choice_index as usize;
                        if slot_idx < 3 {
                            state.core.players[1 - p_idx].set_tapped(slot_idx, true);
                        }
                        ctx.choice_index = -1; // FIXED
                    },
                    O_TAP_MEMBER => {
                        if ctx.choice_index == -1 {
                            // First Pass: Optional?
                            if (a & 0x02) != 0 {
                                let choice_text = get_choice_text(db, &ctx);
                                if !suspend_interaction(state, db, &ctx, instr_ip, O_TAP_MEMBER, 0, "OPTIONAL", &choice_text, a as u64, -1) { continue; }
                                return;
                            }
                            
                            // Forced selection (a & 0x01)
                            if (a & 0x01) != 0 {
                                let choice_text = get_choice_text(db, &ctx);
                                if !suspend_interaction(state, db, &ctx, instr_ip, O_TAP_MEMBER, 0, "TAP_M_SELECT", &choice_text, a as u64, v as i16) { continue; }
                                return;
                            }

                            // No selection triggered? Just tap the target.
                            let target_type = s; 
                            let slot = resolve_target_slot(target_type, &ctx);
                            if slot < 3 { state.core.players[p_idx].set_tapped(slot, true); }
                            ctx.choice_index = -1;
                        } else {
                            // RESUMPTION
                            if (a & 0x02) != 0 {
                                // Resumed from OPTIONAL
                                if ctx.choice_index == 1 { 
                                    ctx.choice_index = -1;
                                    continue; 
                                }
                                // Chose YES (0) -> Now tap the target
                                let target_type = s;
                                let slot = resolve_target_slot(target_type, &ctx);
                                if slot < 3 { state.core.players[p_idx].set_tapped(slot, true); }
                                ctx.choice_index = -1;
                            } else {
                                // Resumed from TAP_M_SELECT
                                let slot = ctx.choice_index as usize;
                                if slot < 3 { state.core.players[p_idx].set_tapped(slot, true); }
                                ctx.choice_index = -1;
                            }
                        }
                    },
                    O_SET_SCORE => state.core.players[p_idx].score = v as u32,
                    O_SEARCH_DECK => {
                        let search_target = ctx.target_slot as usize;
                        if search_target < state.core.players[p_idx].deck.len() {
                            let cid = state.core.players[p_idx].deck.remove(search_target);
                            match s {
                                4 => {
                                    let slot = a as usize; // a usually contains the target slot during search response processing if not mapped
                                    if slot < 3 {
                                        if let Some(old) = state.handle_member_leaves_stage(p_idx, slot, db, &ctx) {
                                            state.core.players[p_idx].discard.push(old);
                                        }
                                        state.core.players[p_idx].stage[slot] = cid;
                                        state.core.players[p_idx].set_tapped(slot, false);
                                        state.core.players[p_idx].set_moved(slot, true);
                                        state.register_played_member(p_idx, cid, db);
                                        let new_ctx = AbilityContext { source_card_id: cid, player_id: p_idx as u8, area_idx: slot as i16, ..Default::default() };
                                        state.trigger_abilities(db, TriggerType::OnPlay, &new_ctx);
                                    } else {
                                        state.core.players[p_idx].hand.push(cid);
                                        state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
                                    }
                                },
                                13 => {
                                    state.core.players[p_idx].success_lives.push(cid);
                                },
                                _ => {
                                    state.core.players[p_idx].hand.push(cid);
                                    state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
                                }
                            }
                            let mut rng = Pcg64::from_os_rng();
                            state.core.players[p_idx].deck.shuffle(&mut rng);
                        }
                    },
                    O_MOVE_TO_DECK => {
                        for _ in 0..(v as usize) {
                            match a {
                                1 => if let Some(cid) = state.core.players[p_idx].discard.pop() { state.core.players[p_idx].deck.push(cid); },
                                4 => {
                                    let slot = ctx.area_idx as usize;
                                    if let Some(cid) = state.handle_member_leaves_stage(p_idx, slot, db, &ctx) {
                                        if state.debug.debug_mode {
                                            println!("[DEBUG] ZONE MOVE: Member Leave: Player {} Slot {} Card {} -> Deck", p_idx, slot, cid);
                                        }
                                        state.core.players[p_idx].deck.push(cid);
                                    }
                                },
                                13 => {
                                    if let Some(cid) = state.core.players[p_idx].success_lives.pop() {
                                        state.core.players[p_idx].deck.push(cid);
                                    }
                                },
                                _ => if let Some(cid) = state.core.players[p_idx].hand.pop() { state.core.players[p_idx].deck.push(cid); }
                            }
                        }
                        let mut rng = Pcg64::from_os_rng();
                        state.core.players[p_idx].deck.shuffle(&mut rng);
                    },
                    O_ORDER_DECK => {
                        if state.core.players[p_idx].looked_cards.is_empty() && v > 0 {
                            if state.core.players[p_idx].deck.len() < v as usize { state.resolve_deck_refresh(p_idx); }
                            for _ in 0..(v as usize).min(state.core.players[p_idx].deck.len()) {
                                if let Some(cid) = state.core.players[p_idx].deck.pop() { state.core.players[p_idx].looked_cards.push(cid); }
                            }
                        }
                        if !state.core.players[p_idx].looked_cards.is_empty() {
                            if ctx.choice_index == -1 {
                                 let choice_text = get_choice_text(db, &ctx);
                                 if !suspend_interaction(state, db, &ctx, instr_ip, O_ORDER_DECK, 0, "ORDER_DECK", &choice_text, 0, -1) { continue; }
                                 return;
                            }
                            let choice = ctx.choice_index;
                            if choice >= 0 && (choice as usize) < state.core.players[p_idx].looked_cards.len() {
                                 let cid = state.core.players[p_idx].looked_cards.remove(choice as usize);
                                 state.core.players[p_idx].deck.push(cid);
                                if !state.core.players[p_idx].looked_cards.is_empty() {
                                    if !suspend_interaction(state, db, &ctx, instr_ip, O_ORDER_DECK, 0, "ORDER_DECK", "", 0, -1) { continue; }
                                    return;
                                }
                            } else {
                                let remainder_mode = a as u8;
                                let looked = std::mem::take(&mut state.core.players[p_idx].looked_cards);
                                if remainder_mode == 1 { state.core.players[p_idx].deck.extend(looked); }
                                else if remainder_mode == 2 { for cid in looked { state.core.players[p_idx].deck.insert(0, cid); } }
                                else { state.core.players[p_idx].discard.extend(looked); }
                            }
                        }
                    },
                    O_SWAP_CARDS => {
                        for _ in 0..(v as usize) {
                            if state.core.players[p_idx].deck.is_empty() { state.resolve_deck_refresh(p_idx); }
                            if let Some(cid) = state.core.players[p_idx].deck.pop() {
                                match target_slot {
                                    7 => state.core.players[p_idx].discard.push(cid),
                                    8 => state.core.players[p_idx].deck.push(cid),
                                    6 => { state.core.players[p_idx].hand.push(cid); state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1); },
                                    _ => state.core.players[p_idx].discard.push(cid),
                                }
                            }
                        }
                    },
                    O_META_RULE => {
                        if a == 0 { state.core.players[p_idx].cheer_mod_count = state.core.players[p_idx].cheer_mod_count.saturating_add(v as u16); }
                    },
                    O_BATON_TOUCH_MOD => state.core.players[p_idx].baton_touch_limit = v as u8,
                    O_TRIGGER_REMOTE => {
                         let target_cid = if target_slot >= 0 && target_slot < 3 { state.core.players[p_idx].stage[target_slot as usize] } else { -1 };
                         if target_cid >= 0 {
                             if let Some(m) = db.get_member(target_cid as i32) {
                                 if (v as usize) < m.abilities.len() {
                                     if sp < MAX_DEPTH {
                                        stack[sp] = (cur_bc, ip, ctx); sp += 1;
                                        stack[sp] = (&m.abilities[v as usize].bytecode, 0, ctx); sp += 1;
                                        break;
                                     }
                                 }
                             }
                         }
                    },
                    O_PLAY_MEMBER_FROM_HAND => {
                        if ctx.choice_index == -1 && !state.core.players[p_idx].hand.is_empty() {
                             if !suspend_interaction(state, db, &ctx, instr_ip, O_PLAY_MEMBER_FROM_HAND, 0, "SELECT_HAND_PLAY", "", a as u64, -1) { continue; }
                             return;
                        }
                        if ctx.choice_index != -1 && ctx.choice_index != 99 {
                            let hand_idx = ctx.choice_index as usize;
                            if hand_idx < state.core.players[p_idx].hand.len() {
                                let cid = state.core.players[p_idx].hand.remove(hand_idx);
                                let slot_idx = resolve_target_slot(s, &ctx);
                                if slot_idx < 3 {
                                    if let Some(old) = state.handle_member_leaves_stage(p_idx, slot_idx, db, &ctx) {
                                        state.core.players[p_idx].discard.push(old);
                                    }
                                    state.core.players[p_idx].stage[slot_idx] = cid;
                                    state.core.players[p_idx].set_tapped(slot_idx, false);
                                    state.core.players[p_idx].set_moved(slot_idx, true);
                                    state.register_played_member(p_idx, cid, db);
                                    let new_ctx = AbilityContext { source_card_id: cid, player_id: p_idx as u8, area_idx: slot_idx as i16, ..Default::default() };
                                    state.trigger_abilities(db, TriggerType::OnPlay, &new_ctx);
                                } else {
                                     // If slot is invalid, return to hand to avoid data loss
                                     state.core.players[p_idx].hand.insert(hand_idx, cid);
                                }
                            }
                        }
                        ctx.choice_index = -1; // FIXED: Prevent choice leakage
                    },
                    O_PLAY_MEMBER_FROM_DISCARD | O_PLAY_LIVE_FROM_DISCARD => {
                         let is_live = real_op == O_PLAY_LIVE_FROM_DISCARD;
                         let mut remaining = if ctx.v_remaining == -1 { v as i16 * 2 } else { ctx.v_remaining };
                         
                         if remaining <= 0 { return; }

                         // Step A: Select Card (even remaining: 4, 2, ...)
                         if remaining % 2 == 0 {
                             if ctx.choice_index == -1 {
                                 state.core.players[p_idx].looked_cards.clear();
                                 for &cid in &state.core.players[p_idx].discard {
                                     let matches = if is_live { db.get_live(cid).is_some() } else { db.get_member(cid).is_some() };
                                     if matches {
                                         state.core.players[p_idx].looked_cards.push(cid);
                                     }
                                 }
                                 if state.core.players[p_idx].looked_cards.is_empty() { return; }
                                 if !suspend_interaction(state, db, &ctx, instr_ip, real_op, 0, "SELECT_DISCARD_PLAY", "", a as u64, remaining) { continue; }
                                 return;
                             }
                             
                             let choice = ctx.choice_index as usize;
                             if choice < state.core.players[p_idx].looked_cards.len() {
                                 let cid = state.core.players[p_idx].looked_cards[choice];
                                 state.core.players[p_idx].looked_cards.clear();
                                 state.core.players[p_idx].looked_cards.push(cid); // Store selected card in index 0
                                 
                                 // Move to Step B: Select Slot (odd remaining: 3, 1, ...)
                                 remaining -= 1;
                                 let choice_type = if is_live { "SELECT_LIVE_SLOT" } else { "SELECT_STAGE" };
                                 if !suspend_interaction(state, db, &ctx, instr_ip, real_op, 0, choice_type, "", a as u64, remaining) { continue; }
                                 return;
                             }
                         } else {
                             // Step B: Already have card in looked_cards[0], now have slot in choice_index
                             if state.core.players[p_idx].looked_cards.is_empty() { return; }
                             let card_id = state.core.players[p_idx].looked_cards.remove(0);
                             let slot_idx = ctx.choice_index as usize;
                             
                             if let Some(pos) = state.core.players[p_idx].discard.iter().position(|&cid| cid == card_id) {
                                 state.core.players[p_idx].discard.remove(pos);
                                 if is_live {
                                     if slot_idx < 10 {
                                         let old = state.core.players[p_idx].live_zone[slot_idx];
                                         if old >= 0 { state.core.players[p_idx].discard.push(old); }
                                         state.core.players[p_idx].live_zone[slot_idx] = card_id;
                                         state.core.players[p_idx].set_revealed(slot_idx, true);
                                     }
                                 } else {
                                     if slot_idx < 3 {
                                         if let Some(old) = state.handle_member_leaves_stage(p_idx, slot_idx, db, &ctx) {
                                             state.core.players[p_idx].discard.push(old);
                                         }
                                         state.core.players[p_idx].stage[slot_idx] = card_id;
                                         state.core.players[p_idx].set_tapped(slot_idx, false);
                                         state.core.players[p_idx].set_moved(slot_idx, true);
                                         state.register_played_member(p_idx, card_id, db);
                                         let new_ctx = AbilityContext { source_card_id: card_id, player_id: p_idx as u8, area_idx: slot_idx as i16, ..Default::default() };
                                         state.trigger_abilities(db, TriggerType::OnPlay, &new_ctx);
                                     }
                                 }
                             }
                             
                             remaining -= 1;
                             if remaining > 0 && !state.core.players[p_idx].discard.is_empty() {
                                 // Jump back to pick next card (reset choice_index for next suspension)
                                 let mut next_ctx = ctx.clone();
                                 next_ctx.choice_index = -1;
                                 next_ctx.v_remaining = remaining;
                                 // We don't return here, we need to loop. 
                                 // In the interpreter, we can jump by setting ip and breaking.
                                 // But since we want to pick next card, we might as well just suspend again.
                                 if !suspend_interaction(state, db, &next_ctx, instr_ip, real_op, 0, "SELECT_DISCARD_PLAY", "", a as u64, remaining) { continue; }
                                 return;
                             }
                         }
                         ctx.choice_index = -1; // FIXED: Final cleanup
                    },
                    O_ADD_STAGE_ENERGY => {
                        let slot = resolve_target_slot(target_slot, &ctx);
                        if slot < 3 {
                            for _ in 0..v { state.core.players[p_idx].stage_energy[slot].push(2000); }
                            state.core.players[p_idx].sync_stage_energy_count(slot);
                        }
                    },
                    O_SET_TAPPED => {
                        let slot = resolve_target_slot(target_slot, &ctx);
                        if slot < 3 { state.core.players[p_idx].set_tapped(slot, v != 0); }
                    },
                    O_MOVE_MEMBER | O_FORMATION_CHANGE => {
                        // O_MOVE_MEMBER priority: Context Area Index > Target Slot
                        // O_FORMATION_CHANGE target_slot==4: Context Area Index
                        let src_slot = if real_op == O_FORMATION_CHANGE && target_slot == 4 { ctx.area_idx as usize } 
                                       else if real_op == O_MOVE_MEMBER && ctx.area_idx >= 0 { ctx.area_idx as usize }
                                       else { resolve_target_slot(target_slot, &ctx) };

                        let dst_slot = if ctx.target_slot != -1 { ctx.target_slot as usize } else { a as usize };
                        if src_slot < 3 && dst_slot < 3 && src_slot != dst_slot {
                            state.core.players[p_idx].swap_slot_data(src_slot, dst_slot);
                             for &slot in &[src_slot, dst_slot] {
                                 let cid = state.core.players[p_idx].stage[slot];
                                 if cid >= 0 {
                                     let mut pos_ctx = ctx.clone();
                                     pos_ctx.source_card_id = cid; pos_ctx.area_idx = slot as i16;
                                     state.trigger_abilities(db, TriggerType::OnPositionChange, &pos_ctx);
                                 }
                             }
                        }
                    },
                    O_PLACE_UNDER => {
                        let slot = if ctx.target_slot != -1 { ctx.target_slot as usize } else { resolve_target_slot(target_slot, &ctx) };
                        if slot < 3 {
                            if a == 0 && !state.core.players[p_idx].hand.is_empty() {
                                // If choice_index is set, use it, else take the last one (simple mode)
                                let hand_idx = if ctx.choice_index != -1 { ctx.choice_index as usize } else { state.core.players[p_idx].hand.len() - 1 };
                                if hand_idx < state.core.players[p_idx].hand.len() {
                                    let cid = state.core.players[p_idx].hand.remove(hand_idx);
                                    state.core.players[p_idx].stage_energy[slot].push(cid);
                                }
                            } else if a == 1 {
                                if let Some(cid) = state.core.players[p_idx].energy_zone.pop() { 
                                    state.core.players[p_idx].stage_energy[slot].push(cid); 
                                }
                            }
                            state.core.players[p_idx].stage_energy_count[slot] = state.core.players[p_idx].stage_energy[slot].len() as u8;
                        }
                        ctx.choice_index = -1;
                    },

                    O_TRANSFORM_COLOR => { state.core.players[p_idx].color_transforms.push((ctx.source_card_id, 0, v as u8)); },
                    O_REDUCE_HEART_REQ => {
                         if (s as usize) < 7 {
                             state.core.players[p_idx].heart_req_reductions.add_to_color(s as usize, v);
                             state.core.players[p_idx].heart_req_reduction_logs.push((ctx.source_card_id, s as u8, v as u8));
                         }
                    },

                    O_SELECT_CARDS => {
                        // v = count
                        // a = filter/attribute
                        // s = target slot (zone?)
                        
                        // If we already have a choice, process it
                        if ctx.choice_index != -1 {
                             if ctx.choice_index == 99 {
                                 cond = false;
                             } else {
                                 cond = true; 
                             }
                        } else {
                            // a as u64 is color mask or flags
                             if !suspend_interaction(state, db, &ctx, instr_ip, O_SELECT_CARDS, 0, "SELECT_HAND_PLAY", "", a as u64, v as i16) { continue; }
                             return;
                        }
                    },
                    O_INCREASE_COST => {
                        state.core.players[p_idx].cost_modifiers.push((Condition {
                            condition_type: ConditionType::None, value: 0, attr: 0, target_slot: 0, is_negated: false, params: serde_json::Value::Null
                        }, v));
                    },
                    O_IMMUNITY => state.core.players[p_idx].set_flag(PlayerState::FLAG_IMMUNITY, v != 0),
                     O_MOVE_TO_DISCARD => {
                        if let Some(res) = handle_move_to_discard(state, db, &mut ctx, v, a, s, instr_ip) {
                            if !res { continue; } // Failed/Ignored but didn't suspend
                        } else {
                            return; // Suspended
                        }
                     },
                    O_REVEAL_UNTIL => {
                        let mut found = false;
                        let mut revealed_count = 0;
                        while !found && !state.core.players[p_idx].deck.is_empty() {
                            // Safety break to prevent infinite loops if deck logic fails
                            if revealed_count > 60 { break; } 

                            if let Some(cid) = state.core.players[p_idx].deck.pop() {
                                revealed_count += 1;
                                
                                // Trigger OnReveal
                                let mut new_ctx = ctx.clone(); new_ctx.source_card_id = cid;
                                state.trigger_abilities(db, TriggerType::OnReveal, &new_ctx);

                                let mut matches = false;
                                 match v {
                                    C_TYPE_CHECK => { // TYPE_CHECK
                                        if let Some(_) = db.get_live(cid as i32) {
                                            if (a & 1) == 1 { matches = true; }
                                        } 
                                    },
                                    C_COST_CHECK => { // COST_GE / COST_CHECK
                                        if let Some(member) = db.get_member(cid) {
                                             let min_cost = ((a & 0x3F) >> 1) as u32;
                                             if member.cost >= min_cost { matches = true; }
                                        }
                                    },
                                    _ => {}
                                }

                                if matches {
                                    // Found! Move to target_slot (usually 6 for Hand)
                                    if target_slot == 6 {
                                        state.core.players[p_idx].hand.push(cid);
                                        state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
                                    } else if target_slot == 7 {
                                        state.core.players[p_idx].discard.push(cid);
                                    }
                                    found = true;
                                } else {
                                    // Not a match, move to discard
                                    state.core.players[p_idx].discard.push(cid);
                                }
                            }
                        }
                    },
                    O_LOOK_AND_CHOOSE => {
                        if let Some(c) = handle_look_and_choose(state, db, &mut ctx, v, a, s, instr_ip) {
                            cond = c;
                        } else {
                            return;
                        }
                    },
                    O_LOOK_DECK | O_REVEAL_CARDS | O_CHEER_REVEAL => {
                        let count = v as usize;
                        state.core.players[p_idx].looked_cards.clear();
                        
                        if target_slot == 6 {
                             if ctx.choice_index == -1 {
                                 if !suspend_interaction(state, db, &ctx, instr_ip, real_op, 0, "REVEAL_HAND", "", (a as u32) as u64, v as i16) { continue; }
                                 return;
                             }
                             
                             let choice = ctx.choice_index as usize;
                             if choice != 99 && choice != 999 {
                                 if choice < state.core.players[p_idx].hand.len() {
                                     let cid = state.core.players[p_idx].hand[choice];
                                     if !state.core.players[p_idx].looked_cards.contains(&cid) {
                                         state.core.players[p_idx].looked_cards.push(cid);
                                     }
                                 }
                             }

                             if ctx.choice_index == 99 || ctx.choice_index == 999 || (v > 0 && ctx.v_remaining == 1) {
                                  // Done
                             } else {
                                 let next_v = if v > 0 { (if ctx.v_remaining > 0 { ctx.v_remaining } else { v as i16 }) - 1 } else { 0 };
                                 if next_v > 0 || v == 0 {
                                     let mut next_ctx = ctx.clone();
                                     next_ctx.v_remaining = next_v;
                                     next_ctx.choice_index = -1;
                                     if !suspend_interaction(state, db, &next_ctx, instr_ip, real_op, 0, "REVEAL_HAND", "", (a as u32) as u64, next_v) { continue; }
                                     return;
                                 }
                             }
                        } else {
                            if state.core.players[p_idx].deck.len() < count { state.resolve_deck_refresh(p_idx); }
                            let deck_len = state.core.players[p_idx].deck.len();
                            let mut revealed_cids = Vec::new();
                            {
                                let p_state = &mut state.core.players[p_idx];
                                for _ in 0..count.min(deck_len) {
                                    if let Some(cid) = p_state.deck.pop() {
                                        p_state.looked_cards.push(cid);
                                        revealed_cids.push(cid);
                                    }
                                }
                            }
                            if real_op != O_LOOK_DECK {
                                for cid in revealed_cids {
                                    let mut new_ctx = ctx.clone(); new_ctx.source_card_id = cid;
                                    state.trigger_abilities(db, TriggerType::OnReveal, &new_ctx);
                                }
                            }
                        }
                    },
                    O_SET_HEARTS => {
                        if (a as usize) < 7 {
                            let targets = if target_slot == 4 && ctx.area_idx >= 0 { vec![ctx.area_idx as usize] } else if target_slot == 1 { vec![0, 1, 2] } else { vec![] };
                            for t in targets { state.core.players[p_idx].heart_buffs[t].set_color_count(a as usize, v as u8); }
                        }
                    },
                    O_SELECT_MEMBER | O_SELECT_LIVE | O_SELECT_PLAYER => {
                        if ctx.choice_index == -1 {
                            let choice_type = if real_op == O_SELECT_MEMBER { "SELECT_MEMBER" } 
                                              else if real_op == O_SELECT_LIVE { "SELECT_LIVE" }
                                              else if real_op == O_SELECT_PLAYER { "SELECT_PLAYER" }
                                              else { "UNKNOWN" };
                            
                            let mut flip_ctx = ctx.clone();
                            if s == 2 { flip_ctx.player_id = 1 - (p_idx as u8); }
                            else if s == 3 { flip_ctx.player_id = 1; }

                            let choice_text = get_choice_text(db, &ctx);
                            if !suspend_interaction(state, db, &flip_ctx, instr_ip, real_op, s, choice_type, &choice_text, a as u64, -1) { continue; }
                            return;
                        }
                        // If we are here, a choice has been made (ctx.choice_index set).
                        ctx.target_slot = ctx.choice_index;
                        // Also update area_idx as some opcodes (like MOVE) might use it as source.
                        if ctx.choice_index < 3 { ctx.area_idx = ctx.choice_index; }
                        // We usually don't DO anything here other than proceed. 
                        // The *next* opcode usually acts on the selection (using `ctx.choice_index` or `target_slot` mapped from it).
                        // `resolve_bytecode` loop clears `choice_index` at formatting `if instr_ip != ctx_in.program_counter ...`.
                        // So `ctx.choice_index` is available for this instruction.
                        // We should probably map it to `ctx.target_slot` if the next instruction expects `s=10`.
                        // But `s=10` pulls from `ctx.target_slot`. 
                        // Does `state.pending_choice` logic auto-update `target_slot`? 
                        // In `game.rs` or `api.rs`, when `process_choice` calls `resolve_bytecode`, it sets `choice_index`.
                        // It does NOT automatically set `target_slot`.
                        // So if we want the selection to persist to `O_JUMP` or `O_MOVE`, we might need to update `ctx.target_slot`?
                        // Actually, standard behavior for "Select X" is often just "pass check".
                        // BUT, if the ability assumes the *next* op uses this selection, we might need to carry it over.
                        // Let's assume standard behavior: The choice is transiently available in `ctx.choice_index` for this instruction.
                        // If logic requires it for future, the bytecode usually writes it somewhere or immediate next op uses it.
                    },
                    O_OPPONENT_CHOOSE => {
                         if ctx.choice_index == -1 {
                              let mut flip_ctx = ctx.clone();
                              flip_ctx.player_id = 1 - (p_idx as u8);
                              let old_cp = state.current_player;
                              state.current_player = 1 - ctx.player_id; // Swap to opponent for choice
                              let choice_text = get_choice_text(db, &ctx);
                             let suspended = suspend_interaction(state, db, &flip_ctx, instr_ip, O_OPPONENT_CHOOSE, 0, "OPPONENT_CHOOSE", &choice_text, 0, -1);
                              if !suspended {
                                  state.current_player = old_cp;
                                  continue;
                              }
                              return;
                         }
                         ctx.player_id = 1 - ctx.player_id; // Flip back
                    },
                    O_PREVENT_ACTIVATE => {
                        let target_p_idx = if s == 1 { 1 - p_idx } else { p_idx };
                        state.core.players[target_p_idx].prevent_activate = 1;
                    },
                    O_PREVENT_BATON_TOUCH => {
                        let target_p_idx = if s == 1 { 1 - p_idx } else { p_idx };
                        state.core.players[target_p_idx].prevent_baton_touch = 1;
                    },
                    O_PREVENT_SET_TO_SUCCESS_PILE => {
                        let target_p_idx = if s == 1 { 1 - p_idx } else { p_idx };
                        state.core.players[target_p_idx].prevent_success_pile_set = 1;
                    },
                    O_PREVENT_PLAY_TO_SLOT => {
                        // Assuming s=slot, a=target_player? Or maybe it targets opponent by default?
                        // Safe bet: a=1 -> Opponent.
                        let target_p_idx = if a == 1 { 1 - p_idx } else { p_idx };
                        if target_slot >= 0 && target_slot < 3 {
                            state.core.players[target_p_idx].prevent_play_to_slot_mask |= 1 << target_slot;
                        }
                    },
                    // NOTE: O_MOVE_TO_DISCARD is handled by the first match arm above (line ~1107)
                    // via handle_move_to_discard()
                    _ => {}
                }
            }
            if state.debug.debug_mode && !cond {
                println!("[DEBUG] BC_SKIP: ip={}, op={} due to cond=false", instr_ip, real_op);
            }
            // CRITICAL: Reset choice_index so it doesn't leak into the next instruction.
            ctx.choice_index = -1;
        }
    }
}

pub fn process_trigger_queue(state: &mut GameState, db: &CardDatabase) {
    while let Some((cid, ab_idx, ctx, is_live, _trigger_type)) = state.trigger_queue.pop_front() {
        if state.phase == Phase::Terminal { break; }
        if is_live {
            if let Some(live) = db.get_live(cid) {
                if (ab_idx as usize) < live.abilities.len() {
                    state.resolve_bytecode(db, &live.abilities[ab_idx as usize].bytecode, &ctx);
                }
            }
        } else {
            if let Some(member) = db.get_member(cid) {
                if (ab_idx as usize) < member.abilities.len() {
                    state.resolve_bytecode(db, &member.abilities[ab_idx as usize].bytecode, &ctx);
                }
            }
        }
        if state.phase == Phase::Response { break; }
    }
}


pub fn get_ability_uid(source_type: u8, id: u32, ab_idx: u32) -> u32 {
    ((source_type as u32) << 24) | (id << 8) | ab_idx
}

pub fn check_once_per_turn(state: &GameState, p_idx: usize, source_type: u8, id: u32, ab_idx: usize) -> bool {
    let uid = get_ability_uid(source_type, id as u32, ab_idx as u32);
    !state.core.players[p_idx].used_abilities.contains(&uid)
}

pub fn consume_once_per_turn(state: &mut GameState, p_idx: usize, source_type: u8, id: u32, ab_idx: usize) {
    let uid = get_ability_uid(source_type, id as u32, ab_idx as u32);
    if !state.core.players[p_idx].used_abilities.contains(&uid) { state.core.players[p_idx].used_abilities.push(uid); }
}

fn handle_move_to_discard(
    state: &mut GameState,
    db: &CardDatabase,
    ctx: &mut AbilityContext,
    v: i32,
    a: i32,
    s: i32,
    instr_ip: usize
) -> Option<bool> {
    let p_idx = ctx.player_id as usize;
    let mut source_zone = (a >> 12) & 0x0F;
    if source_zone == 0 {
        // Fallback for legacy bytecode: Use 's' if it looks like a zone (4, 6, 13)
        // If 's' is 1 or 2 (Player ID), we default to 6 (Hand) if it's MOVE_TO_DISCARD usually.
        if s == 4 || s == 6 || s == 13 {
            source_zone = s;
        } else {
            source_zone = 6; // Default to Hand for MOVE_TO_DISCARD if unknown
        }
    }
    let count = if v == 0 { 1 } else { v };
    
    // Rule: FLAG_IMMUNITY protects against opponent's discard effects.
    // If the target for discard is NOT the player who owns the ability, check for immunity.
    // Note: This logic assumes that if we are targeting opponent's hand/stage/etc., it's an opponent-directed effect.
    // In SID, you generally only discard your own cards unless it's a specific 'opponent discards' card.
    // We check if the target player is immune.
    let target_player_idx = if (a & 0x10) != 0 { 1 - p_idx } else { p_idx }; 
    if target_player_idx != p_idx && state.core.players[target_player_idx].get_flag(PlayerState::FLAG_IMMUNITY) {
        if state.debug.debug_mode { println!("[DEBUG] Player {} is immune to discard effect from Player {}", target_player_idx, p_idx); }
        return Some(false);
    }
    
    if (a & 0x02) != 0 && ctx.choice_index == -1 && !state.ui.silent {
        // Resource check: Only prompt if enough cards exist in the source zone
        let available_count = match source_zone {
            6 => state.core.players[target_player_idx].hand.len() as i32,
            4 => state.core.players[target_player_idx].stage.iter().filter(|&&c| c >= 0).count() as i32,
            13 => state.core.players[target_player_idx].energy_zone.len() as i32,
            _ => 99, // Unknown zone, assume possible to avoid skipping unintentionally
        };

        if available_count < v {
            return Some(false);
        } else {
            if !suspend_interaction(state, db, ctx, instr_ip, O_MOVE_TO_DISCARD as i32, s, "OPTIONAL", "", (a as u32) as u64, -1i16) { return Some(true); }
            return None;
        }
    }
    
    let mut next_ctx = ctx.clone();
    if (a & 0x02) != 0 && ctx.choice_index != -1 && ctx.v_remaining == -1 {
         if ctx.choice_index == 1 || ctx.choice_index == 99 { return Some(false); }
         next_ctx.choice_index = -1; // Consume the YES
    }
    
    let choice_type = if source_zone == 6 { "SELECT_HAND_DISCARD" } else { "SELECT_DISCARD" };
    
    // Auto-Select Self logic for Stage Sacrifice (count=1)
    if source_zone == 4 && next_ctx.choice_index == -1 && count == 1 {
        let slot = if next_ctx.area_idx >= 0 { next_ctx.area_idx as usize } else { 0 };
        if slot < 3 && state.core.players[p_idx].stage[slot] == ctx.source_card_id {
            next_ctx.choice_index = slot as i16;
        }
    }

    if next_ctx.choice_index == -1 && count > 0 && source_zone != 0 && !state.ui.silent {
         if !suspend_interaction(state, db, &next_ctx, instr_ip, O_MOVE_TO_DISCARD as i32, s, choice_type, "", a as u64, count as i16) { return Some(true); }
         return None;
    }
    
    if next_ctx.choice_index != -1 {
        let idx = next_ctx.choice_index as usize;
        let mut removed_cid = -1;
        match source_zone {
            6 => if idx < state.core.players[p_idx].hand.len() {
                removed_cid = state.core.players[p_idx].hand[idx];
                if removed_cid != -1 {
                    state.core.players[p_idx].hand[idx] = -1; // Tombstone
                } else {
                    removed_cid = -1; // Already a tombstone
                }
            },
            4 => {
                let slot = if idx < 3 { idx } else if next_ctx.area_idx >= 0 { next_ctx.area_idx as usize } else { 0 };
                if let Some(cid) = state.handle_member_leaves_stage(p_idx, slot, db, &next_ctx) {
                    removed_cid = cid;
                }
            },
            13 => if !state.core.players[p_idx].success_lives.is_empty() { removed_cid = state.core.players[p_idx].success_lives.pop().unwrap() as i32; },
            0 => if !state.core.players[p_idx].deck.is_empty() { removed_cid = state.core.players[p_idx].deck.pop().unwrap() as i32; },
            3 => {
                if !state.core.players[p_idx].energy_zone.is_empty() {
                    removed_cid = state.core.players[p_idx].energy_zone.pop().unwrap() as i32;
                    
                }
            },
            _ => {
                println!("WARNING: handle_move_to_discard unknown source_zone={}", source_zone);
            }
        }
        if removed_cid >= 0 {
            state.core.players[p_idx].discard.push(removed_cid as i32);
            next_ctx.v_remaining = if next_ctx.v_remaining > 0 { next_ctx.v_remaining - 1 } else { (count as i16) - 1 };
            if next_ctx.v_remaining > 0 {
                next_ctx.choice_index = -1;
                if !suspend_interaction(state, db, &next_ctx, instr_ip, O_MOVE_TO_DISCARD as i32, s, choice_type, "", (a as u32) as u64, next_ctx.v_remaining) { return Some(true); }
                return None;
            }
        }
    } else {
        // ... (Auto discard can stay as pop since it's usually mandatory/final)
        for _ in 0..count {
            match source_zone {
                6 => if let Some(cid) = state.core.players[p_idx].hand.pop() { state.core.players[p_idx].discard.push(cid); },
                4 => {
                    let slot = if next_ctx.area_idx >= 0 { next_ctx.area_idx as usize } else { 0 };
                    if let Some(cid) = state.handle_member_leaves_stage(p_idx, slot, db, &next_ctx) {
                        state.core.players[p_idx].discard.push(cid as i32);
                    }
                },
                13 => if let Some(cid) = state.core.players[p_idx].success_lives.pop() { state.core.players[p_idx].discard.push(cid); },
                0 => if let Some(cid) = state.core.players[p_idx].deck.pop() { state.core.players[p_idx].discard.push(cid); },
                3 => {
                    if let Some(cid) = state.core.players[p_idx].energy_zone.pop() {
                        state.core.players[p_idx].discard.push(cid);
                    }
                },
                _ => {}
            }
        }
    }
    // Compaction before returning Some(true)
    state.core.players[p_idx].hand.retain(|c| *c != -1);
    Some(true)
}

fn handle_look_and_choose(
    state: &mut GameState,
    db: &CardDatabase,
    ctx: &mut AbilityContext,
    v: i32,
    a: i32,
    s: i32,
    instr_ip: usize
) -> Option<bool> {
    let p_idx = ctx.player_id as usize;
    let target_slot = s & 0xFF; // Bits 0-7: Target Slot
    let rem_dest = (s >> 8) & 0xFF; // Bits 8-15: Remainder Destination (7=Discard, 8=Deck, 6=Hand, 1=Top, 2=Bottom)
    let source_zone = (a >> 12) & 0x0F;
    let source_zone = if source_zone == 0 { 8 } else { source_zone as i32 }; // Default to Deck (8)
    
    // Unpack v: look_count | (pick_count << 8)
    let look_count = (v & 0xFF) as usize;
    let pick_count_raw = ((v >> 8) & 0xFF) as usize;

    if state.core.players[p_idx].looked_cards.is_empty() {
        state.core.players[p_idx].looked_cards.clear(); // Safety: Ensure clean slate
        let reveal_count = if source_zone == 6 { state.core.players[p_idx].hand.len() }
                           else if source_zone == 7 { state.core.players[p_idx].discard.len() }
                           else if source_zone == 15 { state.core.players[p_idx].yell_cards.len() }
                           else { look_count };
                           
        match source_zone {
            6 => {
                for _ in 0..reveal_count {
                    if let Some(cid) = state.core.players[p_idx].hand.pop() { state.core.players[p_idx].looked_cards.push(cid); }
                }
            },
            7 => {
                for _ in 0..reveal_count {
                    if let Some(cid) = state.core.players[p_idx].discard.pop() { state.core.players[p_idx].looked_cards.push(cid); }
                }
            },
            15 => {
                let y_cards = std::mem::take(&mut state.core.players[p_idx].yell_cards);
                state.core.players[p_idx].looked_cards.extend(y_cards);
            },
            _ => {
                if state.core.players[p_idx].deck.len() < reveal_count { state.resolve_deck_refresh(p_idx); }
                for _ in 0..reveal_count.min(state.core.players[p_idx].deck.len()) {
                    if let Some(cid) = state.core.players[p_idx].deck.pop() { state.core.players[p_idx].looked_cards.push(cid); }
                }
            }
        }
    }

    if ctx.choice_index == -1 {
         let choice_type = if source_zone == 6 { "SELECT_HAND_DISCARD" } else { "LOOK_AND_CHOOSE" };
         let choice_text = get_choice_text(db, ctx);
         
          let pick_count = ((v >> 8) & 0xFF) as i16;
          let v_rem = if pick_count > 0 { pick_count } else { 1 };
          
          // Multi-Character Filter Support
          // ID1 is packed in v (16-22). ID2/ID3 are in a (17-23, 24-30).
          // Color Mask is packed in v (23-29).
          let char_id_1 = ((v >> 16) & 0x7F) as u64;
          let mut filter_attr = (a as u32) as u64;
          if char_id_1 > 0 {
              filter_attr |= 1u64 << 42; // Enable Character Filter Mode
              filter_attr |= (char_id_1 & 0x7F) << 31; // Pack ID1 into available slot
          }

          let color_mask = ((v >> 23) & 0x7F) as u64;
          if color_mask > 0 {
              filter_attr |= 1u64 << 31; // Enable Color Filter Mode
              filter_attr |= color_mask << 32; // Pack mask into bits 32-38
          }

          if !suspend_interaction(state, db, ctx, instr_ip, O_LOOK_AND_CHOOSE as i32, s, choice_type, &choice_text, filter_attr, v_rem) {
              // Rule: If no matches found, we skip the interaction but MUST still handle the remainder.
              // We fall through to the remainder handling logic below.
              // But first we need to make sure `revealed` is taken from `looked_cards`.
          } else {
              return None;
          }
     }
     
    let choice = ctx.choice_index;
    let mut revealed = std::mem::take(&mut state.core.players[p_idx].looked_cards); // Initialize revealed here
    if choice == 99 {
        // Skipped — proceed straight to remainder handling (after compaction)
        ctx.choice_index = -1; // FIXED: Choice leakage
    } else {
        if choice >= 0 && (choice as usize) < revealed.len() && choice != 999 {
            let chosen = revealed[choice as usize];
            if chosen != -1 {
                revealed[choice as usize] = -1; // Leave a tombstone
                
                // Destination logic: prioritize explicit target_slot (s) from bytecode
                // over a-bit flags, since filter values in `a` can have low bits set
                // that would falsely trigger destination overrides.
                let destination = if target_slot > 0 { target_slot }
                                 else if (a & 0x01) != 0 { 7 } 
                                 else if (a & 0x02) != 0 { 8 } 
                                 else if (a & 0x04) != 0 { 4 } 
                                 else { 6 };

                 match destination {
                     7 => { state.core.players[p_idx].discard.push(chosen); },
                     8 => { state.core.players[p_idx].deck.push(chosen); },
                     4 => {
                         let slot = s as usize;
                         if slot < 3 {
                            if let Some(cid) = state.handle_member_leaves_stage(p_idx, slot, db, &ctx) {
                                state.core.players[p_idx].discard.push(cid as i32);
                            }
                            state.core.players[p_idx].stage[slot] = chosen;
                            state.core.players[p_idx].set_tapped(slot, false);
                            state.core.players[p_idx].set_moved(slot, true);
                            state.register_played_member(p_idx, chosen, db);
                            let new_ctx = AbilityContext { source_card_id: chosen, player_id: p_idx as u8, area_idx: slot as i16, ..Default::default() };
                            state.trigger_abilities(db, TriggerType::OnPlay, &new_ctx);
                         } else {
                             state.core.players[p_idx].hand.push(chosen);
                             state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
                         }
                    },
                    13 => { state.core.players[p_idx].success_lives.push(chosen); },
                    6 | _ => {
                        state.core.players[p_idx].hand.push(chosen);
                        state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
                    }
                 }
                 
                 if source_zone == 15 {
                     // Remove picked card from actual energy zone
                     for slot in 0..3 {
                          if let Some(pos) = state.core.players[p_idx].stage_energy[slot].iter().position(|&c| c == chosen) {
                              state.core.players[p_idx].stage_energy[slot].remove(pos);
                              state.core.players[p_idx].sync_stage_energy_count(slot);
                              break;
                          }
                     }
                 }
                 
                 // Multi-pick logic
                 let effective_pick_count = if pick_count_raw > 0 { pick_count_raw } else { look_count };
                 let rem = if ctx.v_remaining > 0 { ctx.v_remaining - 1 } else { (effective_pick_count as i16).saturating_sub(1) };
                 let has_more_cards = revealed.iter().any(|&c| c != -1);

                 if rem > 0 && has_more_cards {
                     state.core.players[p_idx].looked_cards = revealed; // Put back for next pick
                     let choice_type = if source_zone == 6 { "SELECT_HAND_DISCARD" } else { "LOOK_AND_CHOOSE" };
                     let choice_text = if let Some(card) = db.get_member(ctx.source_card_id) {
                         card.name.clone()
                     } else if let Some(live) = db.get_live(ctx.source_card_id) {
                         live.name.clone()
                     } else { String::new() };
                     
                      if !suspend_interaction(state, db, ctx, instr_ip, O_LOOK_AND_CHOOSE as i32, s, choice_type, &choice_text, (a as u32) as u64, rem) { return Some(true); }
                      return None;
                 }
            }
         }
    }
     
     // Remainder handling (when all picks done or skip)
     // `revealed` already holds the cards from the first take above.
     // First, filter out tombstones
     revealed.retain(|c| *c != -1);

     if !revealed.is_empty() {
         // Determine where remainder goes based on explicit param or source
         let dest = if rem_dest > 0 { rem_dest } else { source_zone as i32 };

         match dest {
             6 => {
                 state.core.players[p_idx].hand.extend(revealed);
             },
             7 => {
                 state.core.players[p_idx].discard.extend(revealed);
              },
              15 => {
                  // Put back to yell cards list (the cache)
                  state.core.players[p_idx].yell_cards.extend(revealed.clone());
              },
              0 | 8 => {
                 state.core.players[p_idx].deck.extend(revealed);
                 let mut rng = Pcg64::from_os_rng();
                 state.core.players[p_idx].deck.shuffle(&mut rng);
             },
             1 => { // Deck Top (No Shuffle)
                 state.core.players[p_idx].deck.extend(revealed);
             },
             2 => { // Deck Bottom
                 for c in revealed.iter().rev() {
                      state.core.players[p_idx].deck.insert(0, *c);
                 }
             },
             _ => {
                 state.core.players[p_idx].discard.extend(revealed);
             },
         }
     }
     
     ctx.choice_index = -1; // FIXED: Choice leakage
     Some(true)
}

fn handle_select_mode(
    state: &mut GameState,
    db: &CardDatabase,
    ctx: &mut AbilityContext,
    v: i32,
    _a: i32,
    _s: i32,
    instr_ip: usize,
    bc: &[i32]
) -> Option<usize> {
    if ctx.choice_index == -1 {
        let choice_text = get_choice_text(db, ctx);
        if !suspend_interaction(state, db, ctx, instr_ip, O_SELECT_MODE, 0, "SELECT_MODE", &choice_text, 0, v as i16) { return Some(instr_ip + 4); }
        return None;
    }

    let choice = ctx.choice_index as usize;
    if choice >= v as usize { 
        ctx.choice_index = -1; // FIXED: Choice leakage
        return Some(instr_ip + 4 + ((v as usize).saturating_sub(2) + 3) / 4 * 4);
    }

    // Read target from the correct position. 
    // Choice 0 is at offset 2 (a), Choice 1 is at offset 3 (s).
    // Choice 2+ are in subsequent 4-byte chunks starting at instr_ip + 4.
    let target = if choice < 2 {
        bc[instr_ip + 2 + choice]
    } else {
        bc[instr_ip + 4 + (choice - 2)]
    };

    let jump_ip = target as usize;
    
    ctx.choice_index = -1; // FIXED: Choice leakage
    Some(jump_ip)
}
fn handle_recovery(
    state: &mut GameState,
    db: &CardDatabase,
    ctx: &mut AbilityContext,
    v: i32,
    _a: i32,
    _s: i32,
    instr_ip: usize,
    real_op: i32
) -> Option<bool> {
    let p_idx = ctx.player_id as usize;
    if ctx.choice_index == -1 {
        state.core.players[p_idx].looked_cards.clear(); // Safety: Ensure clean slate
        if state.core.players[p_idx].looked_cards.is_empty() {
            if real_op == O_RECOVER_LIVE {
                for &cid in &state.core.players[p_idx].discard {
                    if db.get_live(cid).is_some() { 
                        state.core.players[p_idx].looked_cards.push(cid); 
                    }
                }
            } else {
                for &cid in &state.core.players[p_idx].discard {
                    if db.get_member(cid).is_some() {
                        state.core.players[p_idx].looked_cards.push(cid);
                    }
                }
            }
        }
        
        if state.core.players[p_idx].looked_cards.is_empty() { return Some(true); }
        
        let choice_type = if real_op == O_RECOVER_LIVE { "RECOV_L" } else { "RECOV_M" };
        let choice_text = get_choice_text(db, ctx);
        if !suspend_interaction(state, db, ctx, instr_ip, real_op, 0, choice_type, &choice_text, 0, -1) { return Some(true); }
        return None;
    }
    
    let choice = ctx.choice_index as usize;
    if choice < state.core.players[p_idx].looked_cards.len() {
        let cid = state.core.players[p_idx].looked_cards[choice];
        if cid != -1 {
            state.core.players[p_idx].looked_cards[choice] = -1; // Tombstone
            state.core.players[p_idx].hand.push(cid);
            state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
            if let Some(pos) = state.core.players[p_idx].discard.iter().position(|&x| x == cid) { state.core.players[p_idx].discard.remove(pos); }
            
            let remaining = if ctx.v_remaining == -1 { v as i16 - 1 } else { ctx.v_remaining - 1 };
            let has_more = state.core.players[p_idx].looked_cards.iter().any(|&c| c != -1);
            
             if remaining > 0 && choice != 999 && has_more {
                  let choice_type = if real_op == O_RECOVER_LIVE { "RECOV_L" } else { "RECOV_M" };
                  let choice_text = get_choice_text(db, ctx);
                  if !suspend_interaction(state, db, ctx, instr_ip, real_op, 0, choice_type, &choice_text, 0, remaining) { return Some(true); }
                  return None;
             }
        }
    }
    // Compaction & Clear (Fix Leak)
    state.core.players[p_idx].looked_cards.clear();
    Some(true)
}

fn handle_swap_zone(
    state: &mut GameState,
    db: &CardDatabase,
    ctx: &mut AbilityContext,
    _v: i32,
    _a: i32,
    _s: i32,
    instr_ip: usize,
) -> Option<bool> {
    let p_idx = ctx.player_id as usize;

    // Step 1: Select success card (Action 600+)
    if ctx.choice_index == -1 && ctx.v_remaining == -1 {
        let cards = state.core.players[p_idx].success_lives.clone();
        if cards.is_empty() { ctx.choice_index = -1; return Some(true); }
        state.core.players[p_idx].looked_cards.clear();
        state.core.players[p_idx].looked_cards.extend(cards);
        
        let choice_text = get_choice_text(db, ctx);
        
        if !suspend_interaction(state, db, ctx, instr_ip, O_SWAP_ZONE, 0, "SELECT_SWAP_SOURCE", &choice_text, 0, 1) { return Some(true); }
        return None;
    }

    // Step 2: picked from success pile, now pick from hand (Action 500+)
    if ctx.v_remaining == 1 {
        let picked_idx = ctx.choice_index as usize;
        if picked_idx >= state.core.players[p_idx].looked_cards.len() { ctx.choice_index = -1; return Some(true); }
        let success_cid = state.core.players[p_idx].looked_cards[picked_idx];
        
        // We reuse choice_index to store picked success_cid? 
        // No, choice_index is what the user SENT.
        // We need to pass the success_cid to the NEXT step.
        // Let's use v_remaining as a marker and store CID in looked_cards[0].
        
        state.core.players[p_idx].looked_cards.clear();
        state.core.players[p_idx].looked_cards.push(success_cid);
        
        let choice_text = get_choice_text(db, ctx);
        
        if !suspend_interaction(state, db, ctx, instr_ip, O_SWAP_ZONE, 0, "SELECT_SWAP_TARGET", &choice_text, 0, 2) { return Some(true); }
        return None;
    }

    // Step 3: picked from hand, perform swap
    if ctx.v_remaining == 2 {
        let success_cid = state.core.players[p_idx].looked_cards[0];
        let hand_picked_idx = ctx.choice_index as usize;
        if hand_picked_idx >= state.core.players[p_idx].hand.len() { ctx.choice_index = -1; return Some(true); }
        
        let hand_cid = state.core.players[p_idx].hand.remove(hand_picked_idx);
        
        // Find success_cid in success_lives and swap
        if let Some(pos) = state.core.players[p_idx].success_lives.iter().position(|&x| x == success_cid) {
            state.core.players[p_idx].success_lives.remove(pos);
            state.core.players[p_idx].success_lives.push(hand_cid);
            state.core.players[p_idx].hand.push(success_cid);
            state.core.players[p_idx].hand_increased_this_turn = state.core.players[p_idx].hand_increased_this_turn.saturating_add(1);
          }
      }
      
     ctx.choice_index = -1; // FIXED: Choice leakage
     state.core.players[p_idx].looked_cards.clear(); // Fix leaked looked cards
      Some(true)
 }
